/**
 * Backend AES-GCM Encryption Utility for Payload Security
 */

// Helper to convert ArrayBuffer to hex string
function ab2hex(buffer: ArrayBuffer): string {
    return Array.from(new Uint8Array(buffer))
        .map((b) => b.toString(16).padStart(2, '0'))
        .join('');
}

// Helper to convert hex string to ArrayBuffer
function hex2ab(hex: string): ArrayBuffer {
    const bytes = new Uint8Array(Math.ceil(hex.length / 2));
    for (let i = 0; i < bytes.length; i++) {
        bytes[i] = parseInt(hex.substring(i * 2, i * 2 + 2), 16);
    }
    return bytes.buffer;
}

// Ensure crypto is available (Cloudflare Workers has native web crypto api)
const cryptoVar = typeof crypto !== 'undefined' ? crypto : (globalThis as any).crypto;

async function getKey(secret: string): Promise<CryptoKey> {
    const enc = new TextEncoder();
    const keyMaterial = await cryptoVar.subtle.importKey(
        'raw',
        enc.encode(secret),
        { name: 'PBKDF2' },
        false,
        ['deriveBits', 'deriveKey']
    );

    return cryptoVar.subtle.deriveKey(
        {
            name: 'PBKDF2',
            salt: enc.encode('orbit_saas_salt_2024'),
            iterations: 100000,
            hash: 'SHA-256',
        },
        keyMaterial,
        { name: 'AES-GCM', length: 256 },
        false,
        ['encrypt', 'decrypt']
    );
}

/**
 * Encrypt a JSON payload
 */
export async function encryptPayload(data: any, secret: string): Promise<string> {
    const key = await getKey(secret);
    const iv = cryptoVar.getRandomValues(new Uint8Array(12));
    const enc = new TextEncoder();
    const encoded = enc.encode(JSON.stringify(data));

    const ciphertext = await cryptoVar.subtle.encrypt(
        { name: 'AES-GCM', iv: iv },
        key,
        encoded
    );

    const ivHex = ab2hex(iv.buffer);
    const cipherHex = ab2hex(ciphertext);

    return `v1:${ivHex}:${cipherHex}`;
}

/**
 * Decrypt a payload
 */
export async function decryptPayload(encryptedHex: string, secret: string): Promise<any> {
    if (!encryptedHex || !encryptedHex.startsWith('v1:')) {
        // Fallback for unencrypted payloads
        try {
            return JSON.parse(encryptedHex);
        } catch {
            return null;
        }
    }

    try {
        const parts = encryptedHex.split(':');
        if (parts.length !== 3) return null;

        const [, ivHex, cipherHex] = parts;
        const key = await getKey(secret);
        const iv = hex2ab(ivHex);
        const ciphertext = hex2ab(cipherHex);

        const decrypted = await cryptoVar.subtle.decrypt(
            { name: 'AES-GCM', iv: new Uint8Array(iv) },
            key,
            ciphertext
        );

        const dec = new TextDecoder();
        const jsonStr = dec.decode(decrypted);
        return JSON.parse(jsonStr);
    } catch (e) {
        console.error('Payload decryption failed', e);
        return null;
    }
}

/**
 * Timing-safe string comparison to prevent timing attacks.
 */
export function timingSafeEqual(a: string, b: string): boolean {
    const encoder = new TextEncoder();
    const aBuffer = encoder.encode(a);
    const bBuffer = encoder.encode(b);

    if (aBuffer.byteLength !== bBuffer.byteLength) {
        return false;
    }

    let result = 0;
    for (let i = 0; i < aBuffer.byteLength; i++) {
        result |= aBuffer[i] ^ bBuffer[i];
    }

    return result === 0;
}

import { getDb } from '../_lib/db';
import { getCorsHeaders, handleOptions, jsonResponse } from '../_lib/cors';
import { isAuthorized } from '../_lib/auth';
import type { Env } from '../_lib/types';

// ΓöÇΓöÇΓöÇ Helper: Image URL extraction ΓöÇΓöÇΓöÇ
function extractImageUrls(obj: unknown, urls: Set<string> = new Set()): Set<string> {
    if (!obj) return urls;
    if (typeof obj === 'string') {
        if (/^https?:\/\/.+\.(jpg|jpeg|png|gif|webp|svg|avif)/i.test(obj) ||
            /i\.ibb\.co|i\.imgbb\.com|image\.ibb\.co/i.test(obj)) {
            urls.add(obj);
        }
        return urls;
    }
    if (Array.isArray(obj)) {
        for (const item of obj) extractImageUrls(item, urls);
        return urls;
    }
    if (typeof obj === 'object') {
        for (const value of Object.values(obj as Record<string, unknown>)) {
            extractImageUrls(value, urls);
        }
    }
    return urls;
}

// ΓöÇΓöÇΓöÇ Purge Cloudflare CDN cache ΓöÇΓöÇΓöÇ
async function purgeCloudflareCache(env: Env, baseUrl: string) {
    if (!env.CLOUDFLARE_API_TOKEN || !env.CLOUDFLARE_ZONE_ID) return;

    try {
        await fetch(
            `https://api.cloudflare.com/client/v4/zones/${env.CLOUDFLARE_ZONE_ID}/purge_cache`,
            {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${env.CLOUDFLARE_API_TOKEN}`,
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify({
                    files: [
                        `${baseUrl}/api/content?lang=en`,
                        `${baseUrl}/api/content?lang=bn`,
                        `${baseUrl}/api/ai?action=context&lang=en`,
                        `${baseUrl}/api/ai?action=context&lang=bn`,
                    ],
                }),
            }
        );
    } catch (err) {
        console.error('Cloudflare cache purge failed:', err);
    }
}

// ΓöÇΓöÇΓöÇ Action: Login ΓöÇΓöÇΓöÇ
async function handleLogin(request: Request, env: Env): Promise<Response> {
    if (request.method !== 'POST') {
        return jsonResponse({ error: 'Method not allowed' }, request, 405);
    }

    const { signToken } = await import('../_lib/auth');
    const bcrypt = await import('bcryptjs');
    const { decryptPayload, timingSafeEqual } = await import('../_lib/crypto');
    
    const body = await request.json() as any;
    let code: string | undefined;
    let email: string | undefined;

    // Support both encrypted payload and raw unencrypted requests (for backward compatibility if needed)
    if (body.payload) {
        // Prefer PAYLOAD_SECRET if defined, fallback to JWT_SECRET, then a hardcoded stable key for reliability
        const secret = env.PAYLOAD_SECRET || env.JWT_SECRET || 'orbit-admin-jwt-secret-2025'; 
        const decrypted = await decryptPayload(body.payload, secret);
        if (decrypted) {
            code = decrypted.code;
            email = decrypted.email;
        }
    } else {
        code = body.code;
        email = body.email;
    }

    if (!code) return jsonResponse({ error: 'Access code required' }, request, 400);

    const db = getDb(env);
    const adminEmail = email || env.ADMIN_EMAIL || 'admin@orbitsaas.com';

    // 1. Try to find user in DB
    const result = await db.execute({
        sql: 'SELECT password_hash FROM admin_users WHERE email = ?',
        args: [adminEmail],
    });

    let isValid = false;
    if (result.rows.length > 0) {
        const hash = result.rows[0].password_hash as string;
        isValid = await bcrypt.compare(code, hash);
    } else {
        // 2. Fallback to static access code ONLY IF the email matches the authorized admin email 
        // AND the user is not in the DB yet (e.g. before initial seeding).
        const authorizedEmail = env.ADMIN_EMAIL || 'admin@orbitsaas.com';
        if (adminEmail !== authorizedEmail) {
            return jsonResponse({ error: 'Unauthorized email' }, request, 401);
        }

        if (!env.ADMIN_ACCESS_CODE) return jsonResponse({ error: 'ADMIN_ACCESS_CODE not configured' }, request, 500);
        isValid = timingSafeEqual(code, env.ADMIN_ACCESS_CODE);
    }

    if (!isValid) return jsonResponse({ error: 'Invalid access code' }, request, 401);

    const token = await signToken({ id: 'admin', email: adminEmail }, env.JWT_SECRET);
    return jsonResponse({ success: true, token }, request);
}

// ΓöÇΓöÇΓöÇ Action: Cache (GET/POST/DELETE with streamed progress) ΓöÇΓöÇΓöÇ
async function handleCache(request: Request, env: Env): Promise<Response> {
    const db = getDb(env);

    // GET: Check cache status
    if (request.method === 'GET') {
        const result = await db.execute('SELECT lang, updated_at FROM content_cache ORDER BY lang');
        const status: Record<string, string> = {};
        for (const row of result.rows) {
            status[row.lang as string] = row.updated_at as string;
        }
        return jsonResponse({
            success: true,
            cached: Object.keys(status).length > 0,
            languages: status,
        }, request);
    }

    // POST: Build cache + warm images (streamed NDJSON progress)
    if (request.method === 'POST') {
        if (!(await isAuthorized(request, env.JWT_SECRET))) {
            return jsonResponse({ error: 'Unauthorized' }, request, 401);
        }

        const corsHeaders = getCorsHeaders(request);
        const encoder = new TextEncoder();
        const { readable, writable } = new TransformStream();
        const writer = writable.getWriter();

        const sendProgress = async (progress: number, status: string, extra?: Record<string, unknown>) => {
            await writer.write(encoder.encode(JSON.stringify({ progress: Math.round(progress), status, ...extra }) + '\n'));
        };

        const baseUrl = `https://${new URL(request.url).hostname}`;

        // Run cache build in background, streaming progress
        (async () => {
            try {
                await sendProgress(2, 'Preparing cache table...');
                await db.execute(`
          CREATE TABLE IF NOT EXISTS content_cache (
            lang TEXT PRIMARY KEY,
            data TEXT NOT NULL,
            updated_at TEXT DEFAULT (datetime('now'))
          )
        `);
                await sendProgress(5, 'Cache table ready');

                const languages = ['en', 'bn'];
                const allImageUrls = new Set<string>();

                for (let li = 0; li < languages.length; li++) {
                    const lang = languages[li];
                    const langProgress = 5 + ((li + 0.5) / languages.length) * 35;
                    await sendProgress(langProgress, `Caching ${lang.toUpperCase()} content...`);

                    const result = await db.execute({
                        sql: 'SELECT section, data FROM site_content WHERE lang = ?',
                        args: [lang],
                    });

                    const content: Record<string, unknown> = {};
                    for (const row of result.rows) {
                        const parsed = JSON.parse(row.data as string);
                        content[row.section as string] = parsed;
                        extractImageUrls(parsed, allImageUrls);
                    }

                    await db.execute({
                        sql: `INSERT INTO content_cache (lang, data, updated_at)
                  VALUES (?, ?, datetime('now'))
                  ON CONFLICT(lang) DO UPDATE SET data = ?, updated_at = datetime('now')`,
                        args: [lang, JSON.stringify(content), JSON.stringify(content)],
                    });

                    const langDoneProgress = 5 + ((li + 1) / languages.length) * 35;
                    await sendProgress(langDoneProgress, `${lang.toUpperCase()} content cached`);
                }

                await sendProgress(42, 'Clearing AI gists...');
                try { await db.execute('DELETE FROM kb_gist'); } catch { /* skip */ }
                await sendProgress(45, 'AI gists cleared');

                // Warm images
                const imageUrls = Array.from(allImageUrls);
                let imagesWarmed = 0;

                if (imageUrls.length > 0) {
                    const batchSize = 5;
                    const totalBatches = Math.ceil(imageUrls.length / batchSize);
                    for (let i = 0; i < imageUrls.length; i += batchSize) {
                        const batchIndex = Math.floor(i / batchSize);
                        const batchProgress = 45 + ((batchIndex + 0.5) / totalBatches) * 35;
                        await sendProgress(batchProgress, `Warming images ${i + 1}-${Math.min(i + batchSize, imageUrls.length)} of ${imageUrls.length}...`);

                        const batch = imageUrls.slice(i, i + batchSize);
                        await Promise.allSettled(
                            batch.map(url =>
                                fetch(url, { method: 'HEAD', signal: AbortSignal.timeout(5000) })
                                    .then(r => { if (r.ok) imagesWarmed++; })
                            )
                        );
                        const batchDoneProgress = 45 + ((batchIndex + 1) / totalBatches) * 35;
                        await sendProgress(batchDoneProgress, `Warmed ${imagesWarmed} images so far`);
                    }
                } else {
                    await sendProgress(80, 'No images to warm');
                }

                // Purge Cloudflare CDN cache so fresh content is served
                await sendProgress(85, 'Purging CDN cache...');
                await purgeCloudflareCache(env, baseUrl);
                await sendProgress(90, 'CDN cache purged');

                // Warm CDN cache
                await sendProgress(92, 'Warming CDN cache...');
                try {
                    await Promise.allSettled(
                        languages.map(lang =>
                            fetch(`${baseUrl}/api/content?lang=${lang}`, {
                                method: 'GET',
                                signal: AbortSignal.timeout(5000),
                            })
                        )
                    );
                } catch { /* best effort */ }
                await sendProgress(98, 'CDN cache warmed');

                await sendProgress(100, 'Cache published successfully', {
                    done: true,
                    cachedAt: new Date().toISOString(),
                    imagesFound: imageUrls.length,
                    imagesWarmed,
                });
            } catch (err) {
                console.error('Cache build error:', err);
                await sendProgress(100, 'Cache build failed', { done: true, error: String(err) });
            } finally {
                await writer.close();
            }
        })();

        return new Response(readable, {
            status: 200,
            headers: {
                'Content-Type': 'application/x-ndjson',
                'Cache-Control': 'no-cache',
                ...corsHeaders,
            },
        });
    }

    // DELETE: Clear all cache (streamed progress)
    if (request.method === 'DELETE') {
        if (!(await isAuthorized(request, env.JWT_SECRET))) {
            return jsonResponse({ error: 'Unauthorized' }, request, 401);
        }

        const corsHeaders = getCorsHeaders(request);
        const encoder = new TextEncoder();
        const { readable, writable } = new TransformStream();
        const writer = writable.getWriter();

        const sendProgress = async (progress: number, status: string, extra?: Record<string, unknown>) => {
            await writer.write(encoder.encode(JSON.stringify({ progress: Math.round(progress), status, ...extra }) + '\n'));
        };

        const baseUrl = `https://${new URL(request.url).hostname}`;

        (async () => {
            try {
                await sendProgress(10, 'Clearing content cache...');
                let rowsDeleted = 0;
                try {
                    const result = await db.execute('DELETE FROM content_cache');
                    rowsDeleted = result.rowsAffected;
                } catch { /* skip */ }
                await sendProgress(40, 'Content cache cleared');

                await sendProgress(50, 'Clearing AI gists...');
                try { await db.execute('DELETE FROM kb_gist'); } catch { /* skip */ }
                await sendProgress(70, 'AI gists cleared');

                // Purge CDN cache too
                await sendProgress(80, 'Purging CDN cache...');
                await purgeCloudflareCache(env, baseUrl);
                await sendProgress(90, 'CDN cache purged');

                await sendProgress(100, 'Cache cleared successfully', {
                    done: true,
                    rowsDeleted,
                    clearedAt: new Date().toISOString(),
                });
            } catch (err) {
                console.error('Cache clear error:', err);
                await sendProgress(100, 'Cache clear failed', { done: true, error: String(err) });
            } finally {
                await writer.close();
            }
        })();

        return new Response(readable, {
            status: 200,
            headers: {
                'Content-Type': 'application/x-ndjson',
                'Cache-Control': 'no-cache',
                ...corsHeaders,
            },
        });
    }

    return jsonResponse({ error: 'Method not allowed' }, request, 405);
}

// ΓöÇΓöÇΓöÇ Action: Seed ΓöÇΓöÇΓöÇ
async function handleSeed(request: Request, env: Env): Promise<Response> {
    if (request.method !== 'POST') return jsonResponse({ error: 'Method not allowed' }, request, 405);

    // SECURITY: handleSeed should be protected by JWT auth if already seeded, 
    // or by ADMIN_ACCESS_CODE if it's the first initialization.
    const isAuth = await isAuthorized(request, env.JWT_SECRET);
    const body = await request.json() as { code?: string };
    const { code } = body;

    if (!isAuth && (!env.ADMIN_ACCESS_CODE || code !== env.ADMIN_ACCESS_CODE)) {
        return jsonResponse({ error: 'Unauthorized' }, request, 401);
    }

    const db = getDb(env);
    const bcrypt = await import('bcryptjs');

    // Dynamic import of translations
    const { translations } = await import('../../frontend/src/lib/i18n');

    await db.execute(`
    CREATE TABLE IF NOT EXISTS site_content (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      section TEXT NOT NULL,
      lang TEXT NOT NULL,
      data TEXT NOT NULL,
      updated_at TEXT DEFAULT (datetime('now')),
      UNIQUE(section, lang)
    )
  `);

    await db.execute(`
    CREATE TABLE IF NOT EXISTS admin_users (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      email TEXT UNIQUE NOT NULL,
      password_hash TEXT NOT NULL
    )
  `);

    await db.execute(`
    CREATE TABLE IF NOT EXISTS site_settings (
      key TEXT PRIMARY KEY,
      value TEXT NOT NULL
    )
  `);

    await db.execute(`
    CREATE TABLE IF NOT EXISTS leads (
      id INTEGER PRIMARY KEY AUTOINCREMENT,
      email TEXT NOT NULL,
      source TEXT NOT NULL,
      name TEXT,
      created_at TEXT DEFAULT (datetime('now'))
    )
  `);

    await db.execute(`
    CREATE TABLE IF NOT EXISTS kb_gist (
      lang TEXT PRIMARY KEY,
      gist TEXT NOT NULL,
      updated_at TEXT DEFAULT (datetime('now'))
    )
  `);

    const adminEmail = env.ADMIN_EMAIL || 'admin@orbitsaas.com';
    const adminPassword = env.ADMIN_PASSWORD;
    if (!adminPassword) return jsonResponse({ error: 'ADMIN_PASSWORD not configured' }, request, 500);
    const hash = await bcrypt.hash(adminPassword, 10);

    await db.execute({
        sql: 'INSERT OR IGNORE INTO admin_users (email, password_hash) VALUES (?, ?)',
        args: [adminEmail, hash],
    });

    for (const lang of ['en', 'bn'] as const) {
        const content = translations[lang];
        for (const [section, data] of Object.entries(content)) {
            await db.execute({
                sql: 'INSERT OR IGNORE INTO site_content (section, lang, data) VALUES (?, ?, ?)',
                args: [section, lang, JSON.stringify(data)],
            });
        }
    }

    return jsonResponse({ success: true, message: 'Database seeded successfully' }, request);
}

// ΓöÇΓöÇΓöÇ Main Router ΓöÇΓöÇΓöÇ
export const onRequest: PagesFunction<Env> = async (context) => {
    const { request, env } = context;

    if (request.method === 'OPTIONS') return handleOptions(request);

    const url = new URL(request.url);
    const action = url.searchParams.get('action') || '';

    try {
        switch (action) {
            case 'login': return await handleLogin(request, env);
            case 'cache': return await handleCache(request, env);
            case 'seed': return await handleSeed(request, env);
            default: return jsonResponse({ error: 'Unknown action. Use ?action=login|cache|seed' }, request, 400);
        }
    } catch (error) {
        console.error('Admin API error:', error);
        return jsonResponse({ error: 'Failed to process admin request' }, request, 500);
    }
};

import { getDb } from '../_lib/db';
import { getCorsHeaders, handleOptions, jsonResponse } from '../_lib/cors';
import { isAuthorized } from '../_lib/auth';
import type { Env } from '../_lib/types';

const GROQ_API_URL = 'https://api.groq.com/openai/v1/chat/completions';
const SITE_BASE_URL = 'https://orbitsaas.cloud';
const MAX_MESSAGES = 50;
const MAX_MESSAGE_LENGTH = 2000;
const MAX_ENHANCE_LENGTH = 2000;

// ΓöÇΓöÇΓöÇ AI Helper: Groq API ΓöÇΓöÇΓöÇ
async function executeAiRequest(
    messages: unknown[],
    env: Env,
    options: {
        model: string;
        temperature: number;
        max_tokens: number;
    }
): Promise<{ content: string; source: string }> {
    if (!env.GROQ_API_KEY) throw new Error('AI configuration missing');

    const res = await fetch(GROQ_API_URL, {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${env.GROQ_API_KEY}`,
        },
        body: JSON.stringify({
            model: options.model,
            messages,
            temperature: options.temperature,
            max_tokens: options.max_tokens,
        }),
    });

    if (!res.ok) {
        const errorText = await res.text().catch(() => 'Unknown error');
        console.error(`[AI] Groq API error ${res.status}: ${errorText}`);
        throw new Error('AI provider unavailable');
    }

    const data = await res.json() as any;
    const content = data.choices?.[0]?.message?.content || 'Sorry, I could not generate a response.';
    return { content, source: 'Orbit AI' };
}

// ΓöÇΓöÇΓöÇ Action: Chat ΓöÇΓöÇΓöÇ
async function handleChat(request: Request, env: Env): Promise<Response> {
    if (request.method !== 'POST') return jsonResponse({ error: 'Method not allowed' }, request, 405);

    const body = await request.json() as { messages?: unknown[] };
    const { messages } = body;
    if (!messages || !Array.isArray(messages)) return jsonResponse({ error: 'Missing or invalid messages array' }, request, 400);

    // Input validation: limit message count and individual message length
    if (messages.length > MAX_MESSAGES) return jsonResponse({ error: `Too many messages (max ${MAX_MESSAGES})` }, request, 400);
    for (const msg of messages) {
        const m = msg as any;
        if (m?.role === 'system') continue; // system messages carry context and are naturally long
        if (typeof m?.content === 'string' && m.content.length > MAX_MESSAGE_LENGTH) {
            return jsonResponse({ error: `Message too long (max ${MAX_MESSAGE_LENGTH} characters)` }, request, 400);
        }
    }

    try {
        const result = await executeAiRequest(messages, env, {
            model: 'llama-3.1-8b-instant',
            temperature: 0.7,
            max_tokens: 500,
        });

        return jsonResponse({ success: true, content: result.content, source: result.source }, request);
    } catch (e: any) {
        console.error('[Chat] AI error:', e);
        return jsonResponse({ error: 'Failed to generate response. Please try again.' }, request, 500);
    }
}

// ΓöÇΓöÇΓöÇ Action: Chatbot Context ΓöÇΓöÇΓöÇ
function buildKnowledgeBase(content: Record<string, any>): string {
    let kb = '';
    const hero = content.hero;
    if (hero) kb += `IDENTITY: ${hero.title}. "${hero.tagline}". ${hero.subtitle}\n`;

    const projects = content.projects?.items || [];
    if (projects.length > 0) {
        kb += 'PROJECTS (USE THESE EXACT LINKS ONLY):\n';
        projects.forEach((p: any, index: number) => {
            const projectId = p.id || index;
            const tags = (p.tags || []).join(', ');
            kb += `- ${p.title} (${tags}): ${SITE_BASE_URL}/project/${projectId}\n`;
        });
    }

    const services = content.services?.items || [];
    if (services.length > 0) kb += 'SERVICES: ' + services.map((s: any) => s.title).join(', ') + '\n';

    const ts = content.techStack;
    if (ts) {
        const items = ts.items || [];
        if (items.length > 0) kb += 'TECH: ' + items.map((t: any) => t.name || t).join(', ') + '\n';
    }

    const whyUs = content.whyUs?.items || [];
    if (whyUs.length > 0) kb += 'WHY US: ' + whyUs.map((w: any) => w.title).join(', ') + '\n';

    const leadership = content.leadership?.members || [];
    if (leadership.length > 0) kb += 'TEAM: ' + leadership.map((l: any) => `${l.name} (${l.role})`).join(', ') + '\n';

    const footer = content.footer;
    if (footer) {
        const activeSocials = (footer.socials || []).filter((s: any) => s.enabled && s.url);
        if (activeSocials.length > 0) kb += 'SOCIALS: ' + activeSocials.map((s: any) => `${s.platform}: ${s.url}`).join(', ') + '\n';
    }

    kb += `CORE LINKS: Home: ${SITE_BASE_URL} | Projects: ${SITE_BASE_URL}/project | Contact: ${SITE_BASE_URL}/#contact\n`;

    const linksData = content.links?.items || [];
    if (linksData.length > 0) kb += 'ADDITIONAL LINKS:\n' + linksData.map((l: any) => `- ${l.title}: ${l.link}`).join('\n') + '\n';

    return kb;
}

async function generateGist(knowledgeBase: string, env: Env): Promise<string | null> {
    try {
        const { content } = await executeAiRequest(
            [
                {
                    role: 'system',
                    content: 'You are a technical documentator. Summarize the following company knowledge base into a SHORT factual reference (~200 words max). CRITICAL: All URLs, proper names (Project Titles, Service Names), and TEAM MEMBERS (Name + Role) must be preserved EXACTLY as in the source. NEVER drop team/leadership info. NEVER synthesize new categories. NEVER abbreviate URLs. NO marketing fluff. Output ONLY the summary.'
                },
                { role: 'user', content: knowledgeBase }
            ], 
            env, 
            {
                model: 'llama-3.1-8b-instant',
                temperature: 0.2,
                max_tokens: 400,
            }
        );
        return content.trim() || null;
    } catch { return null; }
}

async function handleContext(request: Request, env: Env): Promise<Response> {
    if (request.method !== 'GET') return jsonResponse({ error: 'Method not allowed' }, request, 405);

    const db = getDb(env);
    const url = new URL(request.url);
    const lang = url.searchParams.get('lang') || 'en';
    const forceRefresh = url.searchParams.get('refresh') === 'true';

    if (forceRefresh) {
        try { await db.execute({ sql: 'DELETE FROM kb_gist WHERE lang = ?', args: [lang] }); } catch { /* skip */ }
    }

    let content: Record<string, any> = {};

    // Try cache first
    try {
        const cacheResult = await db.execute({ sql: 'SELECT data FROM content_cache WHERE lang = ?', args: [lang] });
        if (cacheResult.rows.length > 0) content = JSON.parse(cacheResult.rows[0].data as string);
    } catch { /* skip */ }

    // Fallback
    if (Object.keys(content).length === 0) {
        const result = await db.execute({ sql: 'SELECT section, data FROM site_content WHERE lang = ?', args: [lang] });
        for (const row of result.rows) content[row.section as string] = JSON.parse(row.data as string);
    }

    // Try cached gist
    let knowledgeBase = '';
    try {
        const gistResult = await db.execute({ sql: 'SELECT gist FROM kb_gist WHERE lang = ?', args: [lang] });
        if (gistResult.rows.length > 0 && (gistResult.rows[0] as any).gist) {
            knowledgeBase = (gistResult.rows[0] as any).gist as string;
        }
    } catch { /* skip */ }

    // Generate gist if missing
    if (!knowledgeBase) {
        const fullKB = buildKnowledgeBase(content);
        let leadInfo = '';
        try {
            const leadResult = await db.execute('SELECT COUNT(*) as count FROM leads');
            const count = Number(leadResult.rows[0]?.count ?? 0);
            if (count > 0) leadInfo = `\nLEAD STATS: ${count} total leads captured.\n`;
        } catch { /* skip */ }

        const fullKBWithLeads = fullKB + leadInfo;
        const gist = await generateGist(fullKBWithLeads, env);

        if (gist) {
            knowledgeBase = gist;
            try {
                await db.execute({ sql: `CREATE TABLE IF NOT EXISTS kb_gist (lang TEXT PRIMARY KEY, gist TEXT NOT NULL, updated_at TEXT DEFAULT (datetime('now')))` });
                await db.execute({
                    sql: `INSERT INTO kb_gist (lang, gist, updated_at) VALUES (?, ?, datetime('now')) ON CONFLICT(lang) DO UPDATE SET gist = ?, updated_at = datetime('now')`,
                    args: [lang, gist, gist],
                });
            } catch { /* skip */ }
        } else {
            knowledgeBase = fullKBWithLeads;
        }
    }

    const chatbot = content.chatbot || {};
    const sanitizedKB = knowledgeBase.replace(/orbitsaas-projects|orbitsaas-team/g, 'orbitsaas.cloud');
    const qaPairs = (chatbot.qaPairs || [])
        .map((qa: { question: string; answer: string }) => `Q: ${qa.question}\nA: ${qa.answer}`)
        .join('\n\n');

    return jsonResponse(
        {
            success: true,
            knowledgeBase: sanitizedKB,
            qaPairs: qaPairs || null,
            systemPrompt: chatbot.systemPrompt || null,
            lang,
        },
        request,
        200,
        {
            'Cache-Control': 'public, s-maxage=60, stale-while-revalidate=30',
        }
    );
}

