      const currentPhrase = phrases[phraseIndex];

      if (!isDeleting) {
        setDisplayText(currentPhrase.substring(0, displayText.length + 1));
        setTypingSpeed(100 + Math.random() * 50);

        if (displayText === currentPhrase) {
          setTimeout(() => setIsDeleting(true), 2000);
