        </div>

        {/* 3. Navigation & Links Grid */}
        <div className="grid grid-cols-2 gap-8">
          <div>
            <h4 className="text-xs font-black text-primary uppercase tracking-[0.2em] mb-4">Navigation</h4>
            <ul className="space-y-3">
              {footerNavLinks.map((link, i) => (
                <li key={i}>
