// 4. Global Delivery ΓÇö Atmospheric Orbital Sphere
const MAP_DATA = [
  "       . . . .   . . . . . .",
  "   . . . . . . . . . . . . . .",
  " . . . . . . . . . . . . . . . .",
  " . . . . . . . . . . . . . . . .",
