import React, { createContext, useContext, useCallback, useMemo } from 'react';
import { translations } from '@/lib/i18n';
import { useQueries, useQueryClient } from '@tanstack/react-query';

type ContentData = Record<string, unknown>;

interface ContentContextValue {
    content: { en: ContentData; bn: ContentData };
    loading: boolean;
    updateSection: (section: string, lang: string, data: unknown) => Promise<boolean>;
    refreshContent: () => Promise<void>;
}

const ContentContext = createContext<ContentContextValue | null>(null);

const API_BASE = import.meta.env.VITE_API_URL || '';

// Deep merge utility to combine defaults with API data
function deepMerge(target: any, source: any) {
    const output = { ...target };
    if (source && typeof source === 'object' && !Array.isArray(source)) {
        Object.keys(source).forEach(key => {
            if (source[key] && typeof source[key] === 'object' && !Array.isArray(source[key])) {
                if (!(key in target)) {
                    Object.assign(output, { [key]: source[key] });
                } else {
                    output[key] = deepMerge(target[key], source[key]);
                }
            } else {
                Object.assign(output, { [key]: source[key] });
            }
        });
    }
    return output;
}

async function fetchContentData(lang: string) {
    const res = await fetch(`${API_BASE}/api/content?lang=${lang}`);
    if (!res.ok) throw new Error('API Error');
    const data = await res.json();
    if (!data.success || Object.keys(data.content).length === 0) {
        throw new Error('No content found');
    }
    return data.content;
}

export function ContentProvider({ children }: { children: React.ReactNode }) {
    const queryClient = useQueryClient();

    const results = useQueries({
        queries: [
            { queryKey: ['content', 'en'], queryFn: () => fetchContentData('en'), staleTime: 30_000, gcTime: 300_000 },
            { queryKey: ['content', 'bn'], queryFn: () => fetchContentData('bn'), staleTime: 30_000, gcTime: 300_000 },
        ],
    });

    const [enQuery, bnQuery] = results;

    // Derived state from queries using deepMerge ΓÇö memoized to prevent cascading re-renders
    const content = useMemo(() => ({
        en: deepMerge(translations.en, enQuery.data || {}),
        bn: deepMerge(translations.bn, bnQuery.data || {}),
    }), [enQuery.data, bnQuery.data]);

    const loading = enQuery.isLoading || bnQuery.isLoading;

    const refreshContent = useCallback(async () => {
        await queryClient.invalidateQueries({ queryKey: ['content'] });
    }, [queryClient]);

    const updateSection = useCallback(async (section: string, lang: string, data: unknown): Promise<boolean> => {
        const token = localStorage.getItem('admin_token');
        if (!token) return false;

        try {
            const res = await fetch(`${API_BASE}/api/content`, {
                method: 'POST',
                headers: {
                    'Content-Type': 'application/json',
                    Authorization: `Bearer ${token}`,
                },
                body: JSON.stringify({ section, lang, data }),
            });

            if (res.ok) {
                // Update cache immediately for better UX
                queryClient.setQueryData(['content', lang], (old: ContentData | undefined) => ({
                    ...old,
                    [section]: data
                }));
                // Short delay then refetch to ensure server has committed
                setTimeout(() => {
                    queryClient.invalidateQueries({ queryKey: ['content', lang] });
                }, 500);
                return true;
            }

            if (res.status === 401) {
                console.warn('[ContentContext] Unauthorized. Token might be expired.');
                localStorage.removeItem('admin_token');
            }
            return false;
        } catch {
            return false;
        }
    }, [queryClient]);

    return (
        <ContentContext.Provider value={{ content, loading, updateSection, refreshContent }}>
            {children}
        </ContentContext.Provider>
    );
}

export function useContent() {
    const ctx = useContext(ContentContext);
    if (!ctx) throw new Error('useContent must be used within ContentProvider');
    return ctx;
}

import { createContext, useContext, useState, type ReactNode } from 'react';
import { translations, type Lang } from '@/lib/i18n';
import { useContent } from './ContentContext';

interface LanguageContextType {
  lang: Lang;
  t: any;
  toggleLang: () => void;
}

const LanguageContext = createContext<LanguageContextType | null>(null);

export function LanguageProvider({ children }: { children: ReactNode }) {
  const [lang, setLang] = useState<Lang>('en');
  const toggleLang = () => setLang(l => (l === 'en' ? 'bn' : 'en'));

  // Try to use dynamic content from API, fallback to i18n.ts
  const { content } = useContent();

  // Use dynamic content from API, fallback to i18n.ts
  const t = content[lang] || translations[lang];

  return (
    <LanguageContext.Provider value={{ lang, t, toggleLang }}>
      {children}
    </LanguageContext.Provider>
  );
}

export function useLang() {
  const ctx = useContext(LanguageContext);
  if (!ctx) throw new Error('useLang must be used within LanguageProvider');
  return ctx;
}

import React, { useEffect, useRef } from 'react';
import { playBoomDirect, warmUpAudio } from './CollisionSound';

interface Rect {
    x: number;
    y: number;
    width: number;
    height: number;
}

interface Props {
    orbitRects: (Rect | null)[]; // O, R, B, I, T
    saasRect: Rect | null;       // SaaS
    onRevealLetter: (index: number) => void;
    onRevealSaaS: () => void;
    onComplete: () => void;
}

const COLORS = ['#f59e0b', '#d97706', '#fbbf24', '#b45309', '#fcd34d'];
const TAU = Math.PI * 2;

export function CometDiceLoaderCanvas({ orbitRects, saasRect, onRevealLetter, onRevealSaaS, onComplete }: Props) {
    const canvasRef = useRef<HTMLCanvasElement>(null);

    // Use refs so the animation loop always reads the latest values
    // without needing to restart the effect
    const orbitRectsRef = useRef(orbitRects);
    const saasRectRef = useRef(saasRect);
    const onRevealLetterRef = useRef(onRevealLetter);
    const onRevealSaaSRef = useRef(onRevealSaaS);
    const onCompleteRef = useRef(onComplete);

    // Keep refs in sync with props (no effect restart needed)
    orbitRectsRef.current = orbitRects;
    saasRectRef.current = saasRect;
    onRevealLetterRef.current = onRevealLetter;
    onRevealSaaSRef.current = onRevealSaaS;
    onCompleteRef.current = onComplete;

    useEffect(() => {
        // Pre-warm audio so the boom is ready by the time the fireball hits (~8s)
        warmUpAudio();

        const cvs = canvasRef.current;
        if (!cvs) return;
        const ctx = cvs.getContext('2d');
        if (!ctx) return;

        let dpr = window.devicePixelRatio || 1;
        let W = window.innerWidth;
        let H = window.innerHeight;

        const resize = () => {
            dpr = window.devicePixelRatio || 1;
            W = window.innerWidth;
            H = window.innerHeight;
            // Set the canvas buffer size (high-res)
            cvs.width = W * dpr;
            cvs.height = H * dpr;
            // CRITICAL: Set the CSS display size to match the viewport exactly
            cvs.style.width = W + 'px';
            cvs.style.height = H + 'px';
        };
        resize();
        window.addEventListener('resize', resize);

        // Dice state
        let diceX = W / 2;
        let diceY = H * 0.25;
        let diceRotX = 0;
        let diceRotY = 0;
        const diceRotZ = 0;
        let diceScale = 1;
        let diceOpacity = 1;

        // Physics for dislocation
        let diceVx = 0;
        let diceVy = 0;
        let gravity = 0;

        // State machine
        let state = 'SPAWNING_ORBIT';
        let stateTimer = 0.8; // Initial delay before first letter
        let lettersRevealed = 0;
        let lastTime = performance.now();
        let floatTime = 0;
        let rafId = 0;

        // Entities
        const comets: any[] = [];
        const particles: any[] = [];

        // ΓöÇΓöÇΓöÇ 3D Cube rendering with optional center text ΓöÇΓöÇΓöÇ
        const drawCube = (cx: number, cy: number, size: number, rx: number, ry: number, rz: number, alpha: number, centerText?: string) => {
            if (alpha <= 0) return;
            ctx.save();
            ctx.translate(cx, cy);
            ctx.globalAlpha = alpha;

            const s = size / 2;
            const vertices = [
                [-s, -s, -s], [s, -s, -s], [s, s, -s], [-s, s, -s],
                [-s, -s, s], [s, -s, s], [s, s, s], [-s, s, s]
            ];

            const cosX = Math.cos(rx), sinX = Math.sin(rx);
            const cosY = Math.cos(ry), sinY = Math.sin(ry);
            const cosZ = Math.cos(rz), sinZ = Math.sin(rz);

            const proj = vertices.map(([x, y, z]) => {
                const y1 = y * cosX - z * sinX;
                const z1 = y * sinX + z * cosX;
                const x2 = x * cosY + z1 * sinY;
                const z2 = -x * sinY + z1 * cosY;
                const x3 = x2 * cosZ - y1 * sinZ;
                const y3 = x2 * sinZ + y1 * cosZ;
                const fov = 300;
                const scale = fov / (fov + z2);
                return { x: x3 * scale, y: y3 * scale, z: z2 };
            });

            const faces = [
                [0, 1, 2, 3], [5, 4, 7, 6], [4, 0, 3, 7],
                [1, 5, 6, 2], [4, 5, 1, 0], [3, 2, 6, 7]
            ];

            const mappedFaces = faces.map(f => {
                const zAvg = (proj[f[0]].z + proj[f[1]].z + proj[f[2]].z + proj[f[3]].z) / 4;
                return { f, zAvg };
            }).sort((a, b) => b.zAvg - a.zAvg);

            mappedFaces.forEach(({ f, zAvg }) => {
                if (zAvg < -size * 0.8) return;
                ctx.beginPath();
                ctx.moveTo(proj[f[0]].x, proj[f[0]].y);
                for (let i = 1; i < 4; i++) ctx.lineTo(proj[f[i]].x, proj[f[i]].y);
                ctx.closePath();
                ctx.fillStyle = 'rgba(10, 10, 10, 0.8)';
                ctx.fill();
                ctx.fillStyle = 'rgba(10, 10, 10, 0.8)';
                ctx.fill();
                ctx.strokeStyle = '#f59e0b';
                ctx.lineWidth = 2.5;
                // Faster alternative to shadowBlur
                ctx.globalAlpha = alpha * 0.3;
                ctx.stroke();
                ctx.globalAlpha = alpha;
                ctx.stroke();
            });

            if (centerText) {
                ctx.fillStyle = '#ffffff';
                ctx.font = `bold ${size * 0.7}px Poppins`;
                ctx.textAlign = 'center';
                ctx.textBaseline = 'middle';
                // Simplify or remove text shadow
                ctx.fillText(centerText, 0, 0);
            }
            ctx.restore();
        };

        const spawnParticles = (x: number, y: number, color: string, count: number, speedMul: number = 1) => {
            for (let i = 0; i < count; i++) {
                const a = Math.random() * TAU;
                const s = (Math.random() * 4 + 2) * speedMul;
                particles.push({
                    x, y,
                    vx: Math.cos(a) * s,
                    vy: Math.sin(a) * s,
                    life: 1,
                    decay: 0.02 + Math.random() * 0.03,
                    color,
                    size: Math.random() * 4 + 2
                });
            }
        };

        const drawComet = (c: any) => {
            ctx.save();
            const dx = c.x - c.lastX;
            const dy = c.y - c.lastY;

            const grad = ctx.createLinearGradient(c.x, c.y, c.x - dx * 5, c.y - dy * 5);
            grad.addColorStop(0, c.color);
            grad.addColorStop(1, 'rgba(0,0,0,0)');

            ctx.beginPath();
            ctx.moveTo(c.x, c.y);
            ctx.lineTo(c.x - dx * 5, c.y - dy * 5);
            ctx.strokeStyle = grad;
            ctx.lineWidth = c.size * 2;
            ctx.lineCap = 'round';
            ctx.stroke();

            // Head glow
            ctx.fillStyle = '#fff';
            ctx.beginPath();
            ctx.arc(c.x, c.y, c.size, 0, TAU);
            ctx.fill();

            // Letter text centered on the comet head
            if (c.text) {
                ctx.fillStyle = '#ffffff';
                ctx.font = `bold ${c.size * 2.5}px Poppins`;
                ctx.textAlign = 'center';
                ctx.textBaseline = 'middle';
                ctx.fillText(c.text, c.x, c.y);
            }
            ctx.restore();
        };

        // ΓöÇΓöÇΓöÇ Helper to get target rect from the LATEST ref ΓöÇΓöÇΓöÇ
        const getLetterTarget = (idx: number) => {
            const rects = orbitRectsRef.current;
            const rect = rects[idx];
            if (rect) return { x: rect.x + rect.width / 2, y: rect.y + rect.height / 2 };
            // Fallback: center of screen
            return { x: W / 2 + (idx - 2) * 60, y: H * 0.45 };
        };

        const getSaasTarget = () => {
            const rect = saasRectRef.current;
            if (rect) return { x: rect.x + rect.width / 2, y: rect.y + rect.height / 2 };
            return { x: W * 0.7, y: H * 0.45 };
        };

        // ΓöÇΓöÇΓöÇ Main render loop ΓöÇΓöÇΓöÇ
        const render = (time: number) => {
            rafId = requestAnimationFrame(render);
            const dt = Math.min((time - lastTime) / 1000, 0.1);
            lastTime = time;

            ctx.clearRect(0, 0, cvs.width, cvs.height);
            ctx.save();
            ctx.scale(dpr, dpr);

            const currentLetter = lettersRevealed < 5 ? ['O', 'R', 'B', 'I', 'T'][lettersRevealed] : '';

            // ΓöÇΓöÇΓöÇ STATE: SPAWNING_ORBIT ΓöÇΓöÇΓöÇ
            if (state === 'SPAWNING_ORBIT') {
                floatTime += dt;
                // Dice floats in a gentle Lissajous pattern in the upper area
                diceX = W / 2 + Math.sin(floatTime * 1.8) * (W * 0.2);
                diceY = H * 0.2 + Math.cos(floatTime * 2.3) * (H * 0.08);

                diceRotX += dt * 3;
                diceRotY += dt * 4;
                stateTimer -= dt;

                if (stateTimer <= 0 && lettersRevealed < 5) {
                    const target = getLetterTarget(lettersRevealed);

                    comets.push({
                        type: 'letter',
                        idx: lettersRevealed,
                        text: currentLetter,
                        x: diceX, y: diceY,
                        lastX: diceX, lastY: diceY,
                        targetX: target.x, targetY: target.y,
                        speed: 600,
                        color: COLORS[lettersRevealed % COLORS.length],
                        size: 7
                    });

                    lettersRevealed++;
                    stateTimer = 1.2; // ~6s for all 5 letters
                } else if (lettersRevealed >= 5 && comets.length === 0) {
                    state = 'AWAITING_COLLISION';
                    stateTimer = 0.8;
                }
            }
            // ΓöÇΓöÇΓöÇ STATE: AWAITING_COLLISION ΓöÇΓöÇΓöÇ
            else if (state === 'AWAITING_COLLISION') {
                floatTime += dt;
                diceX = W / 2 + Math.sin(floatTime * 1.8) * (W * 0.2);
                diceY = H * 0.2 + Math.cos(floatTime * 2.3) * (H * 0.08);

                diceRotX += dt * 3;
                diceRotY += dt * 4;
                stateTimer -= dt;

                if (stateTimer <= 0) {
                    comets.push({
                        type: 'strike',
                        text: null,
                        x: -200, y: H * 0.15,
                        lastX: -200, lastY: H * 0.15,
                        targetX: diceX, targetY: diceY,
                        speed: 2000,
                        color: '#ef4444',
                        size: 15
                    });
                    state = 'COLLIDING';
                }
            }
            // ΓöÇΓöÇΓöÇ STATE: COLLIDING ΓöÇΓöÇΓöÇ
            else if (state === 'COLLIDING') {
                diceRotX += dt * 3;
                diceRotY += dt * 4;
            }
            // ΓöÇΓöÇΓöÇ STATE: DISLOCATING ΓöÇΓöÇΓöÇ
            else if (state === 'DISLOCATING') {
                const saasTarget = getSaasTarget();

                diceVy += gravity * dt;
                diceVx *= 0.98;
                diceX += diceVx * dt;
                diceY += diceVy * dt;

                diceRotX += diceVx * dt * 0.01;
                diceRotY += diceVy * dt * 0.01;

                const dist = Math.hypot(diceX - saasTarget.x, diceY - saasTarget.y);

                // Homing force
                const f = 15;
                diceVx += (saasTarget.x - diceX) * f * dt;
                diceVy += (saasTarget.y - diceY) * f * dt;
                diceVx *= 0.92;
                diceVy *= 0.92;

                // Trail particles
                if (Math.random() > 0.5) {
                    particles.push({
                        x: diceX + (Math.random() - 0.5) * 20,
                        y: diceY + (Math.random() - 0.5) * 20,
                        vx: -diceVx * 0.1, vy: -diceVy * 0.1,
                        life: 1, decay: 0.05, color: '#f59e0b', size: 3
                    });
                }

                if (dist < 40) {
                    state = 'BURSTING';
                    stateTimer = 0.4;
                    onRevealSaaSRef.current();
                    spawnParticles(diceX, diceY, '#f59e0b', 50, 3);
                    spawnParticles(diceX, diceY, '#fbbf24', 50, 4);
                }
            }
            // ΓöÇΓöÇΓöÇ STATE: BURSTING ΓöÇΓöÇΓöÇ
            else if (state === 'BURSTING') {
                diceScale += dt * 10;
                diceOpacity -= dt * 3;
                if (diceOpacity <= 0) {
                    state = 'DONE';
                    stateTimer = 0.5;
                }
            }
            // ΓöÇΓöÇΓöÇ STATE: DONE ΓöÇΓöÇΓöÇ
            else if (state === 'DONE') {
                stateTimer -= dt;
                if (stateTimer <= 0) {
                    onCompleteRef.current();
                    cancelAnimationFrame(rafId);
                }
            }

            // ΓöÇΓöÇΓöÇ RENDER COMETS ΓöÇΓöÇΓöÇ
            for (let i = comets.length - 1; i >= 0; i--) {
                const c = comets[i];
                c.lastX = c.x; c.lastY = c.y;

                // For letter comets, continuously update target from latest DOM rects
                if (c.type === 'letter') {
                    const target = getLetterTarget(c.idx);
                    c.targetX = target.x;
                    c.targetY = target.y;
                }

                const dx = c.targetX - c.x;
                const dy = c.targetY - c.y;
                const dist = Math.hypot(dx, dy);

                if (dist < c.speed * dt) {
                    c.x = c.targetX;
                    c.y = c.targetY;

                    if (c.type === 'letter') {
                        onRevealLetterRef.current(c.idx);
                        spawnParticles(c.x, c.y, c.color, 30);
                        // Play a subtler 20% volume sound for each letter reveal
                        playBoomDirect(0.2);
                    } else if (c.type === 'strike') {
                        spawnParticles(c.x, c.y, '#ef4444', 40, 3);
                        spawnParticles(c.x, c.y, '#f97316', 40, 2);
                        state = 'DISLOCATING';

                        // Play the boom sound on fireball impact
                        playBoomDirect();

                        const saasTarget = getSaasTarget();
                        diceVx = (saasTarget.x - diceX) * 2.5;
                        diceVy = -800;
                        gravity = 2500;
                    }
                    comets.splice(i, 1);
                } else {
                    c.x += (dx / dist) * c.speed * dt;
                    c.y += (dy / dist) * c.speed * dt;
                    drawComet(c);
                }
            }

            // ΓöÇΓöÇΓöÇ RENDER PARTICLES ΓöÇΓöÇΓöÇ
            for (let i = particles.length - 1; i >= 0; i--) {
                const p = particles[i];
                p.x += p.vx;
                p.y += p.vy;
                p.life -= p.decay;

                if (p.life <= 0) {
                    particles.splice(i, 1);
                } else {
                    ctx.globalAlpha = p.life;
                    ctx.fillStyle = p.color;
                    ctx.beginPath();
                    ctx.arc(p.x, p.y, p.size * p.life, 0, TAU);
                    ctx.fill();
                }
            }

            // ΓöÇΓöÇΓöÇ RENDER MAIN DICE ΓöÇΓöÇΓöÇ
            if (diceOpacity > 0 && state !== 'DONE') {
                const rawSize = W < 768 ? 50 : 70;
                drawCube(diceX, diceY, rawSize * diceScale, diceRotX, diceRotY, diceRotZ, diceOpacity, currentLetter);
            }

            ctx.restore();
        };

        rafId = requestAnimationFrame(render);

        return () => {
            cancelAnimationFrame(rafId);
            window.removeEventListener('resize', resize);
        };
        // IMPORTANT: empty deps ΓÇö effect runs once, reads latest props via refs
    }, []);

    return (
        <canvas
            ref={canvasRef}
            className="fixed inset-0 z-50 pointer-events-none"
        />
    );
}

import { useRef, useState, useEffect, useCallback } from 'react';
import { motion, useInView } from 'framer-motion';
import { useLang } from '@/contexts/LanguageContext';
import { useContent } from '@/contexts/ContentContext';
import { Helmet } from 'react-helmet-async';
import { Link } from 'react-router-dom';
import { ArrowUpRight, FolderOpen } from 'lucide-react';

// --- Types ---
interface ProjectItem {
    id: string;
    title: string;
    desc: string;
    images?: string[];
    image?: string;
    category?: string;
    categories?: string[];
    featured?: boolean;
    order?: number;
    _originalIndex: number;
    _id: string;
    tags?: string[];
}

// --- Cinematic Project Card (Light Theme) ---
function CinematicCard({ item, i }: { item: ProjectItem; i: number }) {
    const routeId = item._id || item._originalIndex;
    const coverImage = item.images?.[0] || item.image || '/placeholder.png';
    const cats: string[] = item.categories || (item.category ? [item.category] : []);
    const ref = useRef<HTMLDivElement>(null);
    const isInView = useInView(ref, { once: true, amount: 0.15 });
    const [isHovered, setIsHovered] = useState(false);

    // Hover Cycling Logic
    const hoverImageUrls: string[] = (() => {
        const indices: number[] = (item as any).hoverImages || [];
        if (indices.length > 0) {
            return indices
                .filter((idx: number) => idx < (item.images?.length || 0))
                .map((idx: number) => item.images![idx]);
        }
        return item.images && item.images.length > 1 ? [item.images[1]] : [];
    })();

    const [activeIndex, setActiveIndex] = useState(-1);
    const [isTransitioning, setIsTransitioning] = useState(false);
    const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

    const clearCycling = useCallback(() => {
        if (intervalRef.current) {
            clearInterval(intervalRef.current);
            intervalRef.current = null;
        }
    }, []);

    useEffect(() => {
        if (isHovered && hoverImageUrls.length > 0) {
            setIsTransitioning(true);
            const t1 = setTimeout(() => {
                setActiveIndex(0);
                setIsTransitioning(false);
            }, 50);

            intervalRef.current = setInterval(() => {
                setIsTransitioning(true);
                const t2 = setTimeout(() => {
                    setActiveIndex((prev: number) => (prev + 1) % hoverImageUrls.length);
                    setIsTransitioning(false);
                }, 300);
            }, 2000);

            return () => {
                clearCycling();
                clearTimeout(t1);
            };
        } else {
            clearCycling();
            if (!isHovered) {
                setIsTransitioning(true);
                const t3 = setTimeout(() => {
                    setActiveIndex(-1);
                    setIsTransitioning(false);
                }, 150);
                return () => clearTimeout(t3);
            }
        }
    }, [isHovered, hoverImageUrls.length, clearCycling]);

    const currentImage = activeIndex >= 0 && activeIndex < hoverImageUrls.length
        ? hoverImageUrls[activeIndex]
        : coverImage;

    return (
        <motion.div
            ref={ref}
            initial={{ opacity: 0, y: 60, scale: 0.97 }}
            animate={isInView ? { opacity: 1, y: 0, scale: 1 } : {}}
            transition={{ duration: 0.8, delay: (i % 3) * 0.12, ease: [0.22, 1, 0.36, 1] }}
            className="group relative"
            onMouseEnter={() => setIsHovered(true)}
            onMouseLeave={() => setIsHovered(false)}
        >
            <Link 
                to={`/project/${routeId}`} 
                className="block relative overflow-hidden rounded-2xl bg-white border border-[#22C55E]/30 transition-all duration-700 hover:border-[#FACC15]/60 hover:shadow-[0_10px_40px_rgba(34,197,94,0.06)]"
            >
                {/* Cover Photo ΓÇö Full 16:9 */}
                <div className="relative aspect-video overflow-hidden">
                    <img
                        src={currentImage}
                        alt={item.title}
                        loading="lazy"
                        draggable="false"
                        className={`w-full h-full object-cover transition-all duration-700 ease-out group-hover:scale-[1.04] no-browser-trigger ${isTransitioning ? 'opacity-0 scale-105' : 'opacity-100'}`}
                    />

                    {/* Shimmer Light Sweep */}
                    <div className="absolute inset-0 pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity duration-500">
                        <div className="absolute inset-0 -translate-x-full group-hover:translate-x-full transition-transform duration-[1.5s] ease-in-out bg-gradient-to-r from-transparent via-white/[0.15] to-transparent" />
                    </div>

                    {/* Bottom Fade */}
                    <div className="absolute inset-x-0 bottom-0 h-24 bg-gradient-to-t from-black/20 to-transparent pointer-events-none" />

                    {/* Featured Badge */}
                    {item.featured && (
                        <div className="absolute top-4 left-4 z-20 px-3 py-1.5 rounded-full bg-[#22C55E]/90 text-white text-[10px] font-bold uppercase tracking-wider backdrop-blur-sm">
                            Γ£ª Featured
                        </div>
                    )}

                    {/* Hover Arrow */}
                    <div className="absolute bottom-5 right-5 z-20 w-10 h-10 rounded-full bg-white/40 backdrop-blur-md border border-white/20 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-all duration-500 group-hover:translate-y-0 translate-y-2">
                        <ArrowUpRight className="w-4 h-4 text-gray-900" />
                    </div>
                </div>

                {/* Content Strip */}
                <div className="p-5 sm:p-6 bg-white">
                    {/* Category Pills */}
                    <div className="flex flex-wrap gap-2 mb-3">
                        {cats.slice(0, 2).map((cat, ci) => (
                            <span
                                key={ci}
                                className="px-2.5 py-1 rounded-full text-[10px] font-bold uppercase tracking-[0.15em] text-[#22C55E] border border-[#22C55E]/10 bg-[#22C55E]/5"
                            >
                                {cat}
                            </span>
                        ))}
                    </div>

                    <h3 className="text-lg sm:text-xl font-bold text-gray-900 leading-tight tracking-tight group-hover:text-[#22C55E] transition-colors duration-500 mb-2">
                        {item.title}
                    </h3>

                    <p className="text-gray-500 text-sm leading-relaxed line-clamp-2">
                        {item.desc?.replace(/<[^>]*>?/gm, '').substring(0, 120)}
                    </p>
                </div>

                {/* Hover Border Glow (Golden) */}
                <div className="absolute inset-0 rounded-2xl pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity duration-700 shadow-[inset_0_0_0_1.5px_#FACC15]" />
            </Link>
        </motion.div>
    );
}

// --- Many More Card ---
function ManyMoreCard({ i }: { i: number }) {
