                            legalLinks,
                            socials,
                        },
                        bn: {
                            brandName: sectionInfo.bn.brandName,
                            rights: sectionInfo.bn.rights,
                            tagline: sectionInfo.bn.tagline,
                            email: sectionInfo.bn.email,
                            phone: sectionInfo.bn.phone,
                            location: sectionInfo.bn.location,
                            mapLink: sectionInfo.bn.mapLink,
                            madeWith: sectionInfo.bn.madeWith,
                            quickLinks,
                            legalLinks,
                            socials,
                        },
                    }}
                    onImport={(parsed) => {
                        if (!parsed.en || !parsed.bn) {
                            toast.error('JSON must have "en" and "bn" keys');
                            return;
                        }
                        setSectionInfo({
                            en: {
                                brandName: parsed.en.brandName || '',
                                rights: parsed.en.rights || '',
                                tagline: parsed.en.tagline || '',
                                email: parsed.en.email || '',
                                phone: parsed.en.phone || '',
                                location: parsed.en.location || '',
                                mapLink: parsed.en.mapLink || '',
                                madeWith: parsed.en.madeWith || '',
                            },
                            bn: {
                                brandName: parsed.bn.brandName || '',
                                rights: parsed.bn.rights || '',
                                tagline: parsed.bn.tagline || '',
                                email: parsed.bn.email || '',
                                phone: parsed.bn.phone || '',
                                location: parsed.bn.location || '',
                                mapLink: parsed.bn.mapLink || '',
                                madeWith: parsed.bn.madeWith || '',
                            },
                        });
                        if (parsed.en.quickLinks) setQuickLinks(parsed.en.quickLinks);
                        if (parsed.en.legalLinks) setLegalLinks(parsed.en.legalLinks);
                        if (parsed.en.socials) setSocials(parsed.en.socials);
                        else if (parsed.bn.socials) setSocials(parsed.bn.socials);
                    }}
                />
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { SectionHeader, LangToggle, SaveButton, TextField, ErrorAlert, useSectionEditor, JsonPanel, ColorField } from '@/components/admin/EditorComponents';
import {
    Globe, Bot, Zap, Smartphone, ShoppingCart, Rocket, Code, Database, Shield, Cloud,
    Cpu, Monitor, Wifi, Mail, Camera, Music, Heart, Star, Target, Briefcase,
    Award, BookOpen, Users, BarChart3, Sparkles, Layers, Settings2, Eye, Palette, Brain, Wrench,
    ChevronDown
} from 'lucide-react';
import type { LucideIcon } from 'lucide-react';

// ΓöÇΓöÇΓöÇ Custom Icons ΓöÇΓöÇΓöÇ
const Bullseye = ({ className, style }: { className?: string; style?: React.CSSProperties }) => (
    <svg className={className} style={style} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
        <path d="M16.5 4A9.5 9.5 0 1 0 20 7.5" />
        <path d="M14 8a4.5 4.5 0 1 0 2 2" />
        <line x1="11" y1="13" x2="20" y2="4" />
        <path d="M14 2h8v8Z" fill="currentColor" stroke="currentColor" />
    </svg>
);

// ΓöÇΓöÇΓöÇ Icon Registry (same as Services/WhyUs) ΓöÇΓöÇΓöÇ
const ICON_MAP: Record<string, LucideIcon | any> = {
    Globe, Bot, Zap, Smartphone, ShoppingCart, Rocket, Code, Database, Shield, Cloud,
    Cpu, Monitor, Wifi, Mail, Camera, Music, Heart, Star, Target, Briefcase,
    Award, BookOpen, Users, BarChart3, Sparkles, Layers, Settings2, Eye, Palette, Brain, Wrench,
    Bullseye
};
const ICON_NAMES = Object.keys(ICON_MAP);

function IconPicker({ label, value, onChange }: { label: string; value: string; onChange: (v: string) => void }) {
    const [open, setOpen] = useState(false);
    const CurrentIcon = ICON_MAP[value] || Target;
    return (
        <div className="relative">
            <label className="text-xs font-medium text-muted-foreground block mb-1">{label}</label>
            <button
                type="button"
                onClick={() => setOpen(!open)}
                className="flex items-center gap-2 px-3 py-2 rounded-lg border border-border bg-background hover:bg-secondary transition-colors text-sm w-full"
            >
                <CurrentIcon className="w-4 h-4 text-primary" />
                <span className="flex-1 text-left">{value || 'Select iconΓÇª'}</span>
                <ChevronDown className={`w-3.5 h-3.5 text-muted-foreground transition-transform ${open ? 'rotate-180' : ''}`} />
            </button>
            {open && (
                <div className="absolute left-0 top-full mt-1 w-72 p-3 bg-popover border border-border rounded-xl shadow-xl z-50 grid grid-cols-7 gap-1.5 max-h-52 overflow-y-auto">
                    {ICON_NAMES.map(name => {
                        const IconCmp = ICON_MAP[name];
                        return (
                            <button
                                key={name}
                                type="button"
                                onClick={() => { onChange(name); setOpen(false); }}
                                className={`p-2 rounded-lg flex items-center justify-center transition-colors ${value === name
                                    ? 'bg-primary text-primary-foreground'
                                    : 'hover:bg-secondary text-muted-foreground hover:text-foreground'
                                    }`}
                                title={name}
                            >
                                <IconCmp className="w-4 h-4" />
                            </button>
                        );
                    })}
                </div>
            )}
        </div>
    );
}

