    const [saving, setSaving] = useState(false);
    const [saved, setSaved] = useState(false);
    const [error, setError] = useState('');

    // ΓöÇΓöÇΓöÇ Load ΓöÇΓöÇΓöÇ
    useEffect(() => {
        if (contentLoading) return;
        if (!content.en) { setLoading(false); return; }

        const enPrivacy = (content.en as any).privacy || {};
        const enTerms = (content.en as any).terms || {};

        setPrivacy({
            title: enPrivacy.title || 'Privacy Policy',
            lastUpdated: enPrivacy.lastUpdated || new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' }),
            sections: enPrivacy.sections || [],
        });
        setTerms({
            title: enTerms.title || 'Terms of Service',
            lastUpdated: enTerms.lastUpdated || new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' }),
            sections: enTerms.sections || [],
        });

        setLoading(false);
    }, [content, contentLoading]);

    // ΓöÇΓöÇΓöÇ Save ΓöÇΓöÇΓöÇ
    const handleSave = async () => {
        setSaving(true);
        setError('');
        setSaved(false);
        const toastId = toast.loading('Saving legal pages...');

        try {
            const pOk = await updateSection('privacy', 'en', privacy);
            const tOk = await updateSection('terms', 'en', terms);

            // Also save to BN (same content, legal pages are typically English-only)
            await updateSection('privacy', 'bn', privacy);
            await updateSection('terms', 'bn', terms);

            if (pOk && tOk) {
                setSaved(true);
                toast.success('Legal pages saved!', { id: toastId });
                await refreshContent();
                setTimeout(() => setSaved(false), 2000);
            } else {
                setError('Error saving legal pages.');
                toast.error('Error saving', { id: toastId });
            }
        } catch (err) {
            console.error(err);
            setError('Failed to save.');
            toast.error('Save failed', { id: toastId });
        } finally {
            setSaving(false);
        }
    };

    // ΓöÇΓöÇΓöÇ Helpers ΓöÇΓöÇΓöÇ
    const currentData = activeTab === 'privacy' ? privacy : terms;
    const setCurrentData = activeTab === 'privacy' ? setPrivacy : setTerms;

    const addSection = () => {
        setCurrentData({ ...currentData, sections: [...currentData.sections, { heading: '', content: '' }] });
    };
    const removeSection = (idx: number) => {
        setCurrentData({ ...currentData, sections: currentData.sections.filter((_, i) => i !== idx) });
    };
    const updateSectionField = (idx: number, field: keyof LegalSection, value: string) => {
        setCurrentData({
            ...currentData,
            sections: currentData.sections.map((s, i) => (i === idx ? { ...s, [field]: value } : s)),
        });
    };
    const moveSection = (idx: number, dir: -1 | 1) => {
        const arr = [...currentData.sections];
        const target = idx + dir;
        if (target < 0 || target >= arr.length) return;
        [arr[idx], arr[target]] = [arr[target], arr[idx]];
        setCurrentData({ ...currentData, sections: arr });
    };

    if (loading) {
        return <div className="p-8 text-center text-muted-foreground">Loading legal pages...</div>;
    }

    return (
        <div className="space-y-6">
            <SectionHeader
                title="Legal Pages"
                description="Manage Privacy Policy and Terms of Service content."
            />
            <ErrorAlert message={error} />

            {/* Tabs */}
            <div className="flex gap-2">
                {(['privacy', 'terms'] as const).map((tab) => (
                    <button
                        key={tab}
                        onClick={() => setActiveTab(tab)}
                        className={`px-4 py-2 rounded-lg text-sm font-medium transition-colors cursor-pointer ${activeTab === tab
                                ? 'bg-primary text-primary-foreground'
                                : 'bg-secondary text-muted-foreground hover:text-foreground'
                            }`}
                    >
                        {tab === 'privacy' ? '≡ƒöÆ Privacy Policy' : '≡ƒôï Terms of Service'}
                    </button>
                ))}
            </div>

            {/* Page Title & Last Updated */}
            <div className="bg-card rounded-xl p-4 md:p-6 border border-border space-y-4">
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    <div>
                        <label className="block text-sm font-medium text-foreground mb-1.5">Page Title</label>
                        <input
                            type="text"
                            value={currentData.title}
                            onChange={(e) => setCurrentData({ ...currentData, title: e.target.value })}
                            className="w-full bg-background rounded-lg px-3 py-2.5 text-sm text-foreground outline-none border border-border"
                        />
                    </div>
                    <div>
                        <label className="block text-sm font-medium text-foreground mb-1.5">Last Updated</label>
                        <input
                            type="text"
                            value={currentData.lastUpdated}
                            onChange={(e) => setCurrentData({ ...currentData, lastUpdated: e.target.value })}
                            placeholder="e.g. March 2, 2026"
                            className="w-full bg-background rounded-lg px-3 py-2.5 text-sm text-foreground outline-none border border-border placeholder:text-muted-foreground/50"
                        />
                    </div>
                </div>
            </div>

            {/* Sections CRUD */}
            <div className="bg-card rounded-xl p-4 md:p-6 border border-border">
                <div className="flex items-center justify-between mb-4">
                    <div>
                        <h3 className="font-semibold text-foreground">
                            Content Sections ({currentData.sections.length})
                        </h3>
                        <p className="text-xs text-muted-foreground mt-1">
                            Each section has a heading and body text. Supports plain text.
                        </p>
                    </div>
                    <button
                        onClick={addSection}
                        className="flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-semibold bg-primary text-primary-foreground hover:opacity-90 transition-opacity cursor-pointer"
                    >
                        <Plus className="w-3.5 h-3.5" /> Add Section
                    </button>
                </div>

                {currentData.sections.length === 0 ? (
                    <p className="text-sm text-muted-foreground/60 italic py-6 text-center">
                        No sections yet. Click "Add Section" to start building the page.
                    </p>
                ) : (
                    <div className="space-y-3">
                        {currentData.sections.map((section, idx) => (
                            <div
                                key={idx}
                                className="rounded-xl border border-border bg-secondary/30 p-4 space-y-3"
                            >
                                <div className="flex items-center justify-between gap-3">
                                    <span className="text-xs text-muted-foreground font-mono bg-background px-2 py-0.5 rounded">
                                        #{idx + 1}
                                    </span>
                                    <div className="flex items-center gap-1">
                                        <button
                                            onClick={() => moveSection(idx, -1)}
                                            disabled={idx === 0}
                                            className="p-1.5 rounded-lg text-muted-foreground hover:text-foreground hover:bg-background transition-colors disabled:opacity-30 cursor-pointer disabled:cursor-default"
                                            title="Move up"
                                        >
                                            <ChevronUp className="w-4 h-4" />
                                        </button>
                                        <button
                                            onClick={() => moveSection(idx, 1)}
                                            disabled={idx === currentData.sections.length - 1}
                                            className="p-1.5 rounded-lg text-muted-foreground hover:text-foreground hover:bg-background transition-colors disabled:opacity-30 cursor-pointer disabled:cursor-default"
                                            title="Move down"
                                        >
                                            <ChevronDown className="w-4 h-4" />
                                        </button>
                                        <button
                                            onClick={() => removeSection(idx)}
                                            className="p-1.5 rounded-lg text-red-500 hover:bg-red-500/10 transition-colors cursor-pointer"
                                            title="Remove section"
                                        >
                                            <Trash2 className="w-4 h-4" />
                                        </button>
                                    </div>
                                </div>
                                <input
                                    type="text"
                                    placeholder="Section Heading (e.g. 1. Information We Collect)"
                                    value={section.heading}
                                    onChange={(e) => updateSectionField(idx, 'heading', e.target.value)}
                                    className="w-full bg-background rounded-lg px-3 py-2.5 text-sm text-foreground font-medium outline-none border border-border placeholder:text-muted-foreground/50"
                                />
                                <textarea
                                    placeholder="Section content..."
                                    value={section.content}
                                    onChange={(e) => updateSectionField(idx, 'content', e.target.value)}
                                    rows={4}
                                    className="w-full bg-background rounded-lg px-3 py-2.5 text-sm text-foreground outline-none border border-border placeholder:text-muted-foreground/50 resize-y min-h-[80px]"
                                />
                            </div>
                        ))}
                    </div>
                )}
            </div>

            <SaveButton onClick={handleSave} saving={saving} saved={saved} />
        </div>
    );
}

import { useState, useEffect } from 'react';
import { useContent } from '@/contexts/ContentContext';
import { SectionHeader, LangToggle, SaveButton, TextField, ErrorAlert, useSectionEditor, ItemListEditor, JsonPanel } from '@/components/admin/EditorComponents';

export default function AdminLinks() {
    const { content } = useContent();
    const { lang, setLang, saving, saved, error, getData, save } = useSectionEditor('links');

    const [formData, setFormData] = useState<{ title: string; items: { title: string; link: string }[] }>({
        title: '',
        items: [],
    });

    // Sync with context data when language changes or data is loaded
    useEffect(() => {
        const data = getData();
        if (data) {
            setFormData({
                title: data.title || '',
                items: data.items || [],
            });
        } else {
            setFormData({ title: '', items: [] });
        }
    }, [lang, getData]);

    const handleSave = () => {
        save(formData);
    };

    const handleFieldChange = (field: keyof typeof formData, value: any) => {
        setFormData(prev => ({ ...prev, [field]: value }));
    };

    const emptyItem = { title: '', link: '' };

    return (
        <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <SectionHeader title="Links Management" description="Manage links accessible by the AI chatbot." />
            <LangToggle lang={lang} setLang={setLang} />
            <ErrorAlert message={error} />

            <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                <div className="lg:col-span-2 space-y-6">
                    <div className="bg-card rounded-2xl p-6 border border-border shadow-sm space-y-4">
                        <h3 className="font-semibold text-lg flex items-center gap-2">
                            <span className="w-8 h-8 rounded-lg bg-primary/10 flex items-center justify-center text-primary">≡ƒöù</span>
                            Links Setup
                        </h3>
                        <TextField
                            label="Section Title (Internal)"
                            value={formData.title}
                            onChange={(value) => handleFieldChange('title', value)}
                            lang={lang}
                        />
                    </div>

                    <div className="bg-card rounded-2xl p-6 border border-border shadow-sm space-y-4">
                        <h3 className="font-semibold text-lg flex items-center gap-2">
                            <span className="w-8 h-8 rounded-lg bg-primary/10 flex items-center justify-center text-primary">≡ƒô¥</span>
                            Link Items
                        </h3>
                        <p className="text-sm text-muted-foreground pb-2">These links will be provided to the AI chatbot to give to users.</p>

                        <ItemListEditor
                            items={formData.items}
                            setItems={(items) => handleFieldChange('items', items)}
                            newItem={emptyItem}
                            renderItem={(item, index, updateItem) => (
                                <div className="space-y-3">
                                    <TextField
                                        label="Link Title"
                                        value={item.title}
                                        onChange={(value) => updateItem({ ...item, title: value })}
                                        lang={lang}
                                    />
                                    <TextField
                                        label="URL (Link)"
                                        value={item.link}
                                        onChange={(value) => updateItem({ ...item, link: value })}
                                    />
                                </div>
                            )}
                        />
                    </div>

                    <SaveButton onClick={handleSave} saving={saving} saved={saved} />
                </div>

                <div className="lg:col-span-1 space-y-6">
                    <JsonPanel
                        data={formData}
                        onImport={(parsed) => setFormData(parsed)}
                        title={`Raw Data (${lang.toUpperCase()})`}
                    />
                    <JsonPanel
                        data={content[lang]?.links}
                        onImport={() => { }}
                        title={`Current Content (${lang.toUpperCase()})`}
                    />
                </div>
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { SectionHeader, LangToggle, SaveButton, TextField, ErrorAlert, useSectionEditor, JsonPanel, ToggleField } from '@/components/admin/EditorComponents';

export default function AdminNavbar() {
    const { lang, setLang, saving, saved, error, getData, save } = useSectionEditor('nav');
    
    // Labels
    const [services, setServices] = useState('');
    const [techStack, setTechStack] = useState('');
    const [whyUs, setWhyUs] = useState('');
    const [leadership, setLeadership] = useState('');
    const [contact, setContact] = useState('');
    const [projects, setProjects] = useState('');
    const [bookCall, setBookCall] = useState('');

    // Visibility
    const [visibility, setVisibility] = useState({
        services: true,
        techStack: true,
        whyUs: true,
        projects: true,
        leadership: true,
        contact: true
    });

    // Custom URLs
    const [urls, setUrls] = useState({
        services: '',
        techStack: '',
        whyUs: '',
        projects: '',
        leadership: '',
        contact: ''
    });


    useEffect(() => {
        const d = getData();
        if (d) {
            setServices(d.services || '');
            setTechStack(d.techStack || '');
            setWhyUs(d.whyUs || '');
            setLeadership(d.leadership || '');
            setContact(d.contact || '');
            setProjects(d.projects || '');
            setBookCall(d.bookCall || '');
            
            if (d.visibility) setVisibility({ ...visibility, ...d.visibility });
            if (d.urls) setUrls({ ...urls, ...d.urls });
        }
    }, [getData]);

    const handleSave = () => {
        save({
            services,
            techStack,
            whyUs,
            leadership,
            contact,
            projects,
            bookCall,
            visibility,
            urls
        });
    };

    const sections: { id: keyof typeof visibility; label: string; value: string; setter: (v: string) => void }[] = [
        { id: 'services', label: 'Services', value: services, setter: setServices },
        { id: 'techStack', label: 'Tech Stack', value: techStack, setter: setTechStack },
        { id: 'whyUs', label: 'Why Us', value: whyUs, setter: setWhyUs },
        { id: 'projects', label: 'Projects', value: projects, setter: setProjects },
        { id: 'leadership', label: 'Leadership', value: leadership, setter: setLeadership },
        { id: 'contact', label: 'Contact', value: contact, setter: setContact },
    ];

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between flex-wrap gap-3">
                <SectionHeader title="Navbar Manager" description="Manage navigation link labels, visibility, and custom URLs." />
                <LangToggle lang={lang} setLang={setLang} />
            </div>
            <ErrorAlert message={error} />
            
            <div className="grid grid-cols-1 gap-6">
                {sections.map(section => (
                    <div key={section.id} className="bg-card rounded-xl p-6 border border-border space-y-4">
                        <div className="flex items-center justify-between border-b border-border pb-4">
                            <h3 className="font-bold text-primary flex items-center gap-2">
                                ≡ƒöù {section.label} Link
                            </h3>
                            <ToggleField 
                                label="Visible in Navbar" 
                                checked={visibility[section.id]} 
                                onChange={(v) => setVisibility({ ...visibility, [section.id]: v })} 
                            />
                        </div>
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                            <TextField 
                                label="Display Label" 
                                value={section.value} 
                                onChange={section.setter} 
                                lang={lang} 
                            />
                            <TextField 
                                label="Custom URL (Optional)" 
                                value={urls[section.id as keyof typeof urls] || ''} 
                                onChange={(v) => setUrls({ ...urls, [section.id]: v })} 
                                lang={lang}
                            />
                        </div>
                        <p className="text-[10px] text-muted-foreground">
                            Leave URL empty for default internal routing. Use full URL (https://...) for external links.
                        </p>
                    </div>
                ))}

                <div className="bg-card rounded-xl p-6 border border-border space-y-4">
                    <h3 className="font-bold text-primary">≡ƒöÿ Special Actions</h3>
                    <TextField label="Book Call Button Text" value={bookCall} onChange={setBookCall} lang={lang} />
                </div>
            </div>

            <SaveButton onClick={handleSave} saving={saving} saved={saved} />

            <div className="mt-8 pt-8 border-t border-border">
                <JsonPanel
                    title={`JSON Import / Export (${lang.toUpperCase()})`}
                    data={{ services, techStack, whyUs, leadership, contact, projects, bookCall, visibility, urls }}
                    onImport={(parsed) => {
                        setServices(parsed.services || '');
                        setTechStack(parsed.techStack || '');
                        setWhyUs(parsed.whyUs || '');
                        setLeadership(parsed.leadership || '');
                        setContact(parsed.contact || '');
                        setProjects(parsed.projects || '');
                        setBookCall(parsed.bookCall || '');
                        if (parsed.visibility) setVisibility(parsed.visibility);
                        if (parsed.urls) setUrls(parsed.urls);
                    }}
                />
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { SectionHeader, LangToggle, SaveButton, TextField, ErrorAlert, useSectionEditor, JsonPanel, ColorField } from '@/components/admin/EditorComponents';
import { Plus, Trash2, GripVertical } from 'lucide-react';
import { Reorder } from 'framer-motion';

export type ProcessFloatingTag = {
    id: string;
    text: string;
    color: string;
    position: string;
};

const POSITIONS = [
    { value: 'top-left', label: 'Top Left' },
    { value: 'top-right', label: 'Top Right' },
    { value: 'center-left', label: 'Center Left' },
    { value: 'center-right', label: 'Center Right' },
    { value: 'bottom-left', label: 'Bottom Left' },
    { value: 'bottom-right', label: 'Bottom Right' }
];

export default function AdminProcess() {
    const { lang, setLang, saving, saved, error, getData, save } = useSectionEditor('process');
    const [tags, setTags] = useState<ProcessFloatingTag[]>([]);

    useEffect(() => {
        const d = getData();
        if (d && d.tags) {
            setTags(d.tags);
        } else {
            // Default MZMedia style tags if empty
            setTags([
                { id: '1', text: 'B2B SaaS', color: '#273FB7', position: 'top-right' },
                { id: '2', text: 'AI Automation', color: '#6366f1', position: 'center-right' },
                { id: '3', text: 'E-Commerce', color: '#8b5cf6', position: 'bottom-right' }
            ]);
        }
    }, [getData]);

    const handleAddTag = () => {
        const newTag: ProcessFloatingTag = {
            id: Date.now().toString(),
            text: 'New Tag',
            color: '#10b981',
            position: 'top-left'
        };
        setTags([...tags, newTag]);
    };

    const updateTag = (id: string, field: keyof ProcessFloatingTag, value: any) => {
        setTags(tags.map(t => t.id === id ? { ...t, [field]: value } : t));
    };

    const removeTag = (id: string) => {
        setTags(tags.filter(t => t.id !== id));
    };

    const currentPayload = { tags };

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between flex-wrap gap-3">
                <SectionHeader title="Process Section" description="Manage Step 1 visual floating tags." />
                <LangToggle lang={lang} setLang={setLang} />
            </div>
            <ErrorAlert message={error} />

            <div className="bg-card rounded-xl p-4 md:p-6 border border-border">
                <div className="flex items-center justify-between mb-4">
                    <h3 className="font-semibold text-foreground">Step 01: Floating Discovery Tags</h3>
                    <button
                        onClick={handleAddTag}
                        className="flex items-center gap-2 px-3 py-1.5 bg-primary/10 text-primary hover:bg-primary/20 transition-colors rounded-lg text-sm font-medium"
                    >
                        <Plus className="w-4 h-4" /> Add Tag
                    </button>
                </div>

                <div className="space-y-3">
                    <Reorder.Group axis="y" values={tags} onReorder={setTags} className="space-y-3">
                        {tags.map((tag) => (
                            <Reorder.Item
                                key={tag.id}
                                value={tag}
                                className="bg-background border border-border rounded-xl p-4 flex flex-col md:flex-row gap-4 items-start md:items-center relative group"
                            >
                                <div className="cursor-grab active:cursor-grabbing p-2 text-muted-foreground hover:text-foreground">
                                    <GripVertical className="w-5 h-5" />
                                </div>
                                <div className="flex-1 min-w-[200px]">
                                    <label className="text-xs font-medium text-muted-foreground block mb-1">Text</label>
                                    <input
                                        type="text"
                                        value={tag.text}
                                        onChange={(e) => updateTag(tag.id, 'text', e.target.value)}
                                        className="w-full px-3 py-2 bg-secondary border border-border rounded-lg text-sm text-foreground focus:ring-1 focus:ring-primary outline-none transition-shadow"
                                    />
                                </div>

                                <div className="w-full md:w-32">
                                    <ColorField label="Background Glow" value={tag.color} onChange={(c) => updateTag(tag.id, 'color', c)} />
                                </div>

                                <div className="w-full md:w-48">
                                    <label className="text-xs font-medium text-muted-foreground block mb-1">Position</label>
                                    <select
                                        value={tag.position}
                                        onChange={(e) => updateTag(tag.id, 'position', e.target.value)}
                                        className="w-full px-3 py-2 bg-secondary border border-border rounded-lg text-sm text-foreground focus:ring-1 focus:ring-primary outline-none"
                                    >
                                        {POSITIONS.map(p => (
                                            <option key={p.value} value={p.value}>{p.label}</option>
                                        ))}
                                    </select>
                                </div>

                                <div className="flex items-center justify-end w-full md:w-auto">
                                    <button
                                        onClick={() => removeTag(tag.id)}
                                        className="p-2 text-red-500 hover:bg-red-500/10 rounded-lg transition-colors flex items-center justify-center h-10 w-10 shrink-0"
                                        title="Remove Tag"
                                    >
                                        <Trash2 className="w-4 h-4" />
                                    </button>
                                </div>
                            </Reorder.Item>
                        ))}
                    </Reorder.Group>
                    {tags.length === 0 && (
                        <div className="text-center py-8 text-muted-foreground text-sm border border-dashed border-border rounded-xl">
                            No floating tags added yet.
                        </div>
                    )}
                </div>
            </div>

            <SaveButton onClick={() => save(currentPayload)} saving={saving} saved={saved} />

            <div className="mt-8 pt-8 border-t border-border">
                <JsonPanel
                    title={`JSON Import / Export (${lang.toUpperCase()})`}
                    data={currentPayload}
                    onImport={(parsed) => {
                        setTags(parsed.tags || []);
                    }}
                />
            </div>
        </div>
    );
}

