export default function AdminProfile() {
    const { lang, setLang, saving, saved, error, getData, save } = useSectionEditor('adminProfile');
    const [data, setData] = useState<ProfileData>({
        name: 'Orbit Admin',
        role: 'Digital Architect',
        avatar: '',
        showSocials: true,
        socials: {}
    });

    useEffect(() => {
        const d = getData();
        if (d) {
            setData({
                name: d.name || 'Orbit Admin',
                role: d.role || 'Digital Architect',
                avatar: d.avatar || '',
                showSocials: d.showSocials ?? true,
                socials: d.socials ? Object.fromEntries(
                    Object.entries(d.socials).map(([k, v]) => [
                        k, 
                        typeof v === 'string' ? { url: v, enabled: true } : (v as any)
                    ])
                ) : {}
            });
        }
    }, [getData, lang]);

    const handleSave = async () => {
        await save(data);
    };

    const updateSocial = (key: keyof ProfileData['socials'], field: 'url' | 'enabled', value: any) => {
        setData(prev => {
            const current = prev.socials[key] || { url: '', enabled: false };
            const normalized = typeof current === 'string' ? { url: current, enabled: true } : current;
            return {
                ...prev,
                socials: { 
                    ...prev.socials, 
                    [key]: { 
                        ...normalized, 
                        [field]: value 
                    } 
                }
            };
        });
    };

    const SocialField = ({ label, platform, icon: Icon }: { label: string, platform: keyof ProfileData['socials'], icon: any }) => {
