            {/* JSON Description Import */}
            {
                (() => {

                    const joinParagraphs = (paras: { heading: string; body: string; color: string }[]) => {
                        return paras.map(p => {
                            if (!p.heading?.trim()) return p.body || '<p><br></p>';
                            const colorAttr = p.color ? ` data-color="${p.color}"` : '';
                            return `<h3${colorAttr}>${p.heading.trim()}</h3>` + (p.body || '<p><br></p>');
                        }).join('<hr>');
                    };

                    const handleParse = () => {
                        setJsonDescError('');
                        try {
                            const parsed = JSON.parse(jsonDescText);

                            // Support both formats:
                            // Format 1: { "en": [...], "bn": [...] }
                            // Format 2: { "en": { "title": "...", "sections": [...] }, "bn": { ... } }
                            const getTitle = (langObj: any) => {
                                if (typeof langObj?.title === 'string') return langObj.title;
                                return null;
                            };

                            const getSections = (langObj: any) => {
                                if (Array.isArray(langObj)) return langObj;
                                if (Array.isArray(langObj?.sections)) return langObj.sections;
                                return null;
                            };

                            const enSections = getSections(parsed.en);
                            const bnSections = getSections(parsed.bn);

                            if (!enSections && !bnSections) {
                                setJsonDescError('JSON must have "en" and/or "bn" with sections array. Click (?) for format.');
                                return;
                            }

                            let updatedItem = { ...item };

                            // Update EN title + description
                            if (enSections) {
                                const enTitle = getTitle(parsed.en);
                                const enParas = enSections.map((s: any) => ({
                                    heading: s.title || '',
                                    body: typeof s.description === 'string' ? (s.description.startsWith('<') ? s.description : `<p>${s.description}</p>`) : '<p><br></p>',
                                    color: ''
                                }));
                                updatedItem = {
                                    ...updatedItem,
                                    en: {
                                        ...updatedItem.en,
                                        ...(enTitle ? { title: enTitle } : {}),
                                        description: joinParagraphs(enParas)
                                    }
                                };
                            }

                            // Update BN title + description
                            if (bnSections) {
                                const bnTitle = getTitle(parsed.bn);
                                const bnParas = bnSections.map((s: any) => ({
                                    heading: s.title || '',
                                    body: typeof s.description === 'string' ? (s.description.startsWith('<') ? s.description : `<p>${s.description}</p>`) : '<p><br></p>',
                                    color: ''
                                }));
                                updatedItem = {
                                    ...updatedItem,
                                    bn: {
                                        ...updatedItem.bn,
                                        ...(bnTitle ? { title: bnTitle } : {}),
                                        description: joinParagraphs(bnParas)
                                    }
                                };
                            }

                            update(updatedItem);
                            toast.success(`Description imported! ${enSections ? enSections.length + ' EN' : ''}${enSections && bnSections ? ' + ' : ''}${bnSections ? bnSections.length + ' BN' : ''} sections. Click "Save Changes" to persist.`);
                            setJsonDescText('');
                            setJsonDescOpen(false);
                        } catch (err: any) {
                            setJsonDescError(`Invalid JSON: ${err.message}`);
                        }
                    };

                    return (
                        <div className="bg-background rounded-xl border border-border overflow-hidden">
                            <button
                                type="button"
                                onClick={() => setJsonDescOpen(!jsonDescOpen)}
                                className="w-full flex items-center justify-between px-5 py-3.5 hover:bg-secondary/30 transition-colors cursor-pointer"
                            >
                                <div className="flex items-center gap-2.5">
                                    <Layers className="w-4.5 h-4.5 text-primary" />
                                    <span className="text-sm font-semibold text-foreground">≡ƒôï JSON Description Import</span>
                                    <span className="text-[10px] text-muted-foreground bg-secondary px-2 py-0.5 rounded-full font-medium">EN + BN</span>
                                </div>
                                <ChevronDown className={`w-4 h-4 text-muted-foreground transition-transform duration-200 ${jsonDescOpen ? 'rotate-180' : ''}`} />
                            </button>

                            {jsonDescOpen && (
                                <div className="px-5 pb-5 space-y-3 border-t border-border pt-4">
                                    <div className="flex items-start justify-between gap-2">
                                        <p className="text-xs text-muted-foreground leading-relaxed">
                                            Paste a JSON object with <code className="bg-secondary px-1 py-0.5 rounded text-primary">"en"</code> and <code className="bg-secondary px-1 py-0.5 rounded text-primary">"bn"</code> keys containing section <code className="bg-secondary px-1 py-0.5 rounded text-primary">title</code> and <code className="bg-secondary px-1 py-0.5 rounded text-primary">description</code> to import for both languages at once.
                                        </p>
                                        <div className="relative">
                                            <button
                                                type="button"
                                                onClick={() => setJsonDescHelp(!jsonDescHelp)}
                                                className="p-1.5 rounded-lg bg-secondary hover:bg-primary/10 text-muted-foreground hover:text-primary transition-colors cursor-pointer"
                                                title="Show format guide"
                                            >
                                                <HelpCircle className="w-4 h-4" />
                                            </button>
                                            {jsonDescHelp && (
                                                <div className="absolute right-0 top-full mt-2 w-[min(420px,calc(100vw-2rem))] p-4 rounded-xl bg-background border border-border shadow-2xl z-50">
                                                    <div className="flex items-center justify-between mb-3">
                                                        <h4 className="text-sm font-bold text-foreground">JSON Format Guide</h4>
                                                        <button onClick={() => setJsonDescHelp(false)} className="text-muted-foreground hover:text-foreground">
                                                            <X className="w-3.5 h-3.5" />
                                                        </button>
                                                    </div>
                                                    <pre className="text-[11px] font-mono text-muted-foreground bg-secondary/50 rounded-lg p-3 overflow-auto max-h-[320px] leading-relaxed whitespace-pre">{`{
  "en": {
    "title": "Project Title (optional)",
    "sections": [
      {
        "title": "Section Title",
        "description": "Section description text"
      },
      {
        "title": "Another Section",
        "description": "More details here"
      }
    ]
  },
  "bn": {
    "title": "αª¬αºìαª░αª£αºçαªòαºìαªƒαºçαª░ αª¿αª╛αª« (αªÉαªÜαºìαª¢αª┐αªò)",
    "sections": [
      {
        "title": "αª╕αºçαªòαª╢αª¿αºçαª░ αª╢αª┐αª░αºïαª¿αª╛αª«",
        "description": "αª╕αºçαªòαª╢αª¿αºçαª░ αª¼αª┐αª¼αª░αªú"
      }
    ]
  }
}`}</pre>
                                                    <div className="mt-3 space-y-1.5 text-[11px] text-muted-foreground">
                                                        <p>ΓÇó <strong>title</strong> (in sections) ΓÇö Section heading displayed as a card title</p>
                                                        <p>ΓÇó <strong>description</strong> ΓÇö Section body text (plain text or HTML)</p>
                                                        <p>ΓÇó <strong>title</strong> (top-level) ΓÇö Sets the project title (optional)</p>
                                                        <p className="text-primary font-medium">Each section becomes a description card on the project page.</p>
                                                    </div>
                                                </div>
                                            )}
                                        </div>
                                    </div>

                                    <textarea
                                        value={jsonDescText}
                                        onChange={e => { setJsonDescText(e.target.value); setJsonDescError(''); }}
                                        placeholder='{ "en": { "title": "...", "sections": [{ "title": "...", "description": "..." }] }, "bn": { ... } }'
                                        rows={8}
                                        className="w-full rounded-lg bg-secondary border border-border p-3 text-xs font-mono text-foreground placeholder:text-muted-foreground/40 focus:outline-none focus:ring-2 focus:ring-primary/30 resize-y"
                                        spellCheck={false}
                                    />

                                    {jsonDescError && (
                                        <div className="flex items-start gap-2 px-3 py-2 rounded-lg bg-destructive/10 border border-destructive/30 text-destructive text-xs">
                                            <span>ΓÜá∩╕Å {jsonDescError}</span>
                                        </div>
                                    )}

                                    <div className="flex items-center gap-2">
                                        <button
                                            type="button"
                                            onClick={handleParse}
                                            disabled={!jsonDescText.trim()}
                                            className="px-4 py-2 rounded-lg bg-primary text-primary-foreground text-xs font-semibold hover:opacity-90 transition-all disabled:opacity-40 cursor-pointer flex items-center gap-1.5"
                                        >
                                            <Layers className="w-3.5 h-3.5" />
                                            Import Description
                                        </button>
                                        <span className="text-[10px] text-muted-foreground">Both EN + BN will be populated. Click "Save Changes" after.</span>
                                    </div>
                                </div>
                            )}
                        </div>
                    );
                })()
            }

            {/* Language Tabs */}
            <div className="bg-background rounded-xl border border-border overflow-hidden">
                <div className="flex border-b border-border bg-secondary/30">
                    <button
                        onClick={() => setTab('en')}
                        className={`flex-1 py-3 text-sm font-medium transition-colors ${tab === 'en' ? 'bg-background border-t-2 border-t-primary text-primary' : 'text-muted-foreground hover:bg-secondary'}`}
                    >
                        English Texts
                    </button>
                    <button
                        onClick={() => setTab('bn')}
                        className={`flex-1 py-3 text-sm font-medium transition-colors ${tab === 'bn' ? 'bg-background border-t-2 border-t-primary text-primary' : 'text-muted-foreground hover:bg-secondary'}`}
                    >
                        αª¼αª╛αªéαª▓αª╛ αªƒαºçαªòαºìαª╕αªƒ (Bangla Texts)
                    </button>
                </div>

                <div className="p-6 space-y-4">
                    <TextField
                        label={tab === 'en' ? "Project Title" : "αª¬αºìαª░αª£αºçαªòαºìαªƒαºçαª░ αª¿αª╛αª«"}
                        value={item[tab].title}
                        onChange={v => updateLoc(tab, 'title', v)}
                        lang={tab}
                    />

                    {/* Multi-Paragraph Description Editor */}
                    {(() => {
                        // Parse existing description into paragraph blocks: split by <h3>
                        const rawDesc = item[tab].description || '';
                        const parseParagraphs = (html: string): { heading: string; body: string; color: string }[] => {
                            if (!html.trim()) return [{ heading: '', body: '', color: '' }];
                            // First split by <hr>, then further split by <h3> within each part
                            const hrParts = html.split(/<hr\s*\/?>/i).filter(p => p.trim());
                            if (hrParts.length === 0) return [{ heading: '', body: html, color: '' }];
                            const result: { heading: string; body: string; color: string }[] = [];
                            for (const hrPart of hrParts) {
                                // Check if this part starts with <h3>
                                const h3Parts = hrPart.split(/(?=<h3[^>]*>)/i).filter(p => p.trim());
                                for (const part of h3Parts) {
                                    const headingMatch = part.match(/^<h3([^>]*)>(.*?)<\/h3>/i);
                                    if (headingMatch) {
                                        const attrs = headingMatch[1];
                                        const colorMatch = attrs.match(/data-color="([^"]*)"/i);
                                        result.push({
                                            heading: headingMatch[2].replace(/<[^>]*>/g, '').trim(),
                                            body: part.replace(/^<h3[^>]*>.*?<\/h3>/i, '').trim(),
                                            color: colorMatch ? colorMatch[1] : ''
                                        });
                                    } else {
                                        result.push({ heading: '', body: part.trim(), color: '' });
                                    }
                                }
                            }
                            return result.length > 0 ? result : [{ heading: '', body: html, color: '' }];
                        };

                        const paragraphs = parseParagraphs(rawDesc);

                        // Join paragraphs back into a single HTML string using <hr> separator
                        const joinParagraphs = (paras: { heading: string; body: string; color: string }[]) => {
                            return paras.map(p => {
                                if (!p.heading.trim()) return p.body || '<p><br></p>';
                                const colorAttr = p.color ? ` data-color="${p.color}"` : '';
                                return `<h3${colorAttr}>${p.heading.trim()}</h3>` + (p.body || '<p><br></p>');
                            }).join('<hr>');
                        };

                        const updateParagraphs = (newParas: { heading: string; body: string; color: string }[]) => {
                            updateLoc(tab, 'description', joinParagraphs(newParas));
                        };

                        return (
                            <div className="space-y-3">
                                <label className="text-sm font-medium text-foreground block">
                                    {tab === 'en' ? 'Description Paragraphs' : 'αª¼αª┐αª¼αª░αªú αªàαª¿αºüαªÜαºìαª¢αºçαªª'}
                                    <span className="text-xs text-muted-foreground ml-2">({paragraphs.length} sections ΓÇö each becomes a card)</span>
                                </label>
                                {paragraphs.map((para, pi) => {
                                    const isCollapsed = !expandedSections.has(pi);
                                    return (
                                        <div key={pi} className="rounded-xl border border-border bg-secondary/30 overflow-hidden relative group">
                                            <div
                                                className="flex items-center justify-between px-4 py-3 cursor-pointer hover:bg-secondary/50 transition-colors"
                                                onClick={() => toggleSection(pi)}
                                            >
                                                <div className="flex items-center gap-2">
                                                    <ChevronDown className={`w-4 h-4 text-muted-foreground transition-transform duration-200 ${isCollapsed ? '-rotate-90' : ''}`} />
                                                    {para.color && <span className="w-2.5 h-2.5 rounded-full flex-shrink-0" style={{ backgroundColor: para.color }} />}
                                                    <span className="text-xs font-bold text-muted-foreground uppercase tracking-wider">
                                                        Section {pi + 1}
                                                    </span>
                                                    {isCollapsed && para.heading && (
                                                        <span className="text-xs text-foreground/60 ml-1 truncate max-w-[200px]">
                                                            ΓÇö {para.heading}
                                                        </span>
                                                    )}
                                                </div>
                                                <div className="flex items-center gap-1" onClick={e => e.stopPropagation()}>
                                                    {pi > 0 && (
                                                        <button
                                                            type="button"
                                                            onClick={() => {
                                                                const updated = [...paragraphs];
                                                                [updated[pi - 1], updated[pi]] = [updated[pi], updated[pi - 1]];
                                                                updateParagraphs(updated);
                                                            }}
                                                            className="p-1 rounded bg-secondary hover:bg-primary/20 text-xs"
                                                            title="Move up"
                                                        >Γåæ</button>
                                                    )}
                                                    {pi < paragraphs.length - 1 && (
                                                        <button
                                                            type="button"
                                                            onClick={() => {
                                                                const updated = [...paragraphs];
                                                                [updated[pi], updated[pi + 1]] = [updated[pi + 1], updated[pi]];
                                                                updateParagraphs(updated);
                                                            }}
                                                            className="p-1 rounded bg-secondary hover:bg-primary/20 text-xs"
                                                            title="Move down"
                                                        >Γåô</button>
                                                    )}
                                                    {paragraphs.length > 1 && (
                                                        <button
                                                            type="button"
                                                            onClick={() => {
                                                                const updated = paragraphs.filter((_, j) => j !== pi);
                                                                updateParagraphs(updated);
                                                            }}
                                                            className="p-1 rounded bg-secondary hover:bg-red-500/20 hover:text-red-400 text-muted-foreground"
                                                            title="Remove section"
                                                        ><Trash2 className="w-3.5 h-3.5" /></button>
                                                    )}
                                                    {onSave && (
                                                        <button
                                                            type="button"
                                                            onClick={onSave}
                                                            className="p-1 px-2 rounded bg-primary/10 text-primary hover:bg-primary/20 text-[10px] font-bold uppercase transition-all"
                                                            title="Save changes"
                                                        >Save</button>
                                                    )}
                                                </div>
                                            </div>
                                            {!isCollapsed && (
                                                <div className="px-4 pb-4 space-y-3">
                                                    <div className="flex items-center gap-2">
                                                        <input
                                                            type="text"
                                                            placeholder={tab === 'en' ? "Section heading (optional, e.g. 'How We Solved the Problem')" : "αª╢αª┐αª░αºïαª¿αª╛αª« (αªÉαªÜαºìαª¢αª┐αªò)"}
                                                            value={para.heading}
                                                            onChange={e => {
                                                                const updated = [...paragraphs];
                                                                updated[pi] = { ...updated[pi], heading: e.target.value };
                                                                updateParagraphs(updated);
                                                            }}
                                                            className="flex-1 bg-background rounded-lg px-4 py-2.5 text-sm text-foreground font-semibold outline-none border border-border placeholder:font-normal placeholder:text-muted-foreground"
                                                        />
                                                        <div className="relative flex items-center gap-1.5">
                                                            <label className="flex items-center gap-1.5 cursor-pointer px-2 py-1.5 rounded-lg border border-border bg-background hover:bg-secondary/50 transition-colors" title="Title color">
                                                                <span
                                                                    className="w-5 h-5 rounded-full border border-border/50 flex-shrink-0"
                                                                    style={{ backgroundColor: para.color || '#ffffff' }}
                                                                />
                                                                <input
                                                                    type="color"
                                                                    value={para.color || '#ffffff'}
                                                                    onChange={e => {
                                                                        const updated = [...paragraphs];
                                                                        updated[pi] = { ...updated[pi], color: e.target.value };
                                                                        updateParagraphs(updated);
                                                                    }}
                                                                    className="sr-only"
                                                                />
                                                            </label>
                                                            {para.color && (
                                                                <button
                                                                    type="button"
                                                                    onClick={() => {
                                                                        const updated = [...paragraphs];
                                                                        updated[pi] = { ...updated[pi], color: '' };
                                                                        updateParagraphs(updated);
                                                                    }}
                                                                    className="p-1 rounded hover:bg-red-500/20 text-muted-foreground hover:text-red-400 transition-colors"
                                                                    title="Reset color"
                                                                >
                                                                    <X className="w-3 h-3" />
                                                                </button>
                                                            )}
                                                        </div>
                                                    </div>
                                                    <RichTextEditor
                                                        label=""
                                                        value={para.body}
                                                        onChange={v => {
                                                            const updated = [...paragraphs];
                                                            updated[pi] = { ...updated[pi], body: v };
                                                            updateParagraphs(updated);
                                                        }}
                                                        lang={tab}
                                                    />
                                                </div>
                                            )}
                                        </div>
                                    );
                                })}
                                <button
                                    type="button"
                                    onClick={() => updateParagraphs([...paragraphs, { heading: '', body: '', color: '' }])}
                                    className="w-full flex items-center justify-center gap-2 py-3 rounded-xl border-2 border-dashed border-border hover:border-primary/50 text-muted-foreground hover:text-primary text-sm font-medium transition-colors"
                                >
                                    <Plus className="w-4 h-4" /> Add Paragraph Section
                                </button>
                            </div>
                        );
                    })()}
                </div>
            </div>
        </div >
    );
}


export default function AdminProjects() {
    const { content, updateSection, refreshContent, loading: contentLoading } = useContent();
    const [loading, setLoading] = useState(true);
    const [projects, setProjects] = useState<UnifiedProject[]>([]);
    const [sectionInfo, setSectionInfo] = useState({
        en: { title: '', subtitle: '' },
        bn: { title: '', subtitle: '' },
    });
    const [categories, setCategories] = useState<string[]>([]);
    const [newCategory, setNewCategory] = useState('');
    const [saving, setSaving] = useState(false);
    const [saved, setSaved] = useState(false);
    const [error, setError] = useState('');
    const [isVisible, setIsVisible] = useState(true);

    // Load and Merge Data on Mount
    useEffect(() => {
        if (!content.en || !content.bn) return;

        const enP = (content.en.projects as any) || { items: [] };
        const bnP = (content.bn.projects as any) || { items: [], categories: [] };

        setIsVisible(enP.visible !== false); // Default to true if not specified
        setCategories(enP.categories || []);

        setSectionInfo({
            en: { title: enP.title || '', subtitle: enP.subtitle || '' },
            bn: { title: bnP.title || '', subtitle: bnP.subtitle || '' }
        });

        const storedCategories = enP.categories || ['SaaS', 'eCommerce', 'Enterprise', 'Education', 'Portfolio', 'Other'];
        setCategories(storedCategories);
        // Merge English and Bangla content
    }, [content]);

    useEffect(() => {
        // If context is still loading, wait.
        if (contentLoading) return;

        // If context is done but data is missing, we should still stop "local" loading to show empty state.
        if (!content.en || !content.bn) {
            setProjects([]);
            setLoading(false);
            return;
        }

        const enItems = (content.en.projects as any)?.items || [];
        const bnItems = (content.bn.projects as any)?.items || [];

        const maxLength = Math.max(enItems.length, bnItems.length);
        const merged: UnifiedProject[] = [];

        for (let i = 0; i < maxLength; i++) {
            const enItem = enItems[i] || {};
            const bnItem = bnItems[i] || {};

            // Prefer shared settings from EN (or BN if EN missing)
            const sharedImages = enItem.images || enItem.image ? (enItem.images || [enItem.image]) : (bnItem.images || (bnItem.image ? [bnItem.image] : []));
            const sharedSeo = enItem.seo || bnItem.seo || { title: '', description: '', keywords: [] };
            // Shared tags: prefer EN, then BN, then empty
            const sharedTags = enItem.tags || bnItem.tags || [];

            // Auto-migrate: category (string) ΓåÆ categories (array)
            const rawCats = enItem.categories || bnItem.categories || (enItem.category ? [enItem.category] : (bnItem.category ? [bnItem.category] : ['SaaS']));
            const sharedCategories = Array.isArray(rawCats) ? rawCats : [rawCats];

            merged.push({
                // Shared
                id: enItem.id || bnItem.id || '',
                order: enItem.order ?? bnItem.order ?? i,
                images: sharedImages,
                hoverImages: enItem.hoverImages || bnItem.hoverImages || [],
                link: enItem.link || bnItem.link || '',
                categories: sharedCategories,
                featured: enItem.featured ?? bnItem.featured ?? false,
                hidden: enItem.hidden ?? bnItem.hidden ?? false,
                videoPreview: enItem.videoPreview || bnItem.videoPreview || '',
                tags: sharedTags,
                seo: sharedSeo,

                // Localized
                en: {
                    title: enItem.title || '',
                    description: enItem.desc || '',
                },
                bn: {
                    title: bnItem.title || '',
                    description: bnItem.desc || '',
                }
            });
        }

        // Sort by order before setting so admin list matches user-facing order
        merged.sort((a, b) => a.order - b.order);
        setProjects(merged);
        setLoading(false);
    }, [content, contentLoading]);

    const handleSave = async () => {
        setSaving(true);
        setError('');
        setSaved(false);
        const toastId = toast.loading('Saving projects...');

        try {
            // 1. Construct EN payload
            const enItems = projects.map(p => ({
                title: p.en.title,
                desc: p.en.description,
                tags: p.tags,
                seo: p.seo,
                id: p.id,
                order: p.order,
                images: p.images,
                hoverImages: p.hoverImages || [],
                image: p.images[0] || '',
                link: p.link,
                categories: p.categories,
                category: p.categories[0] || 'SaaS',
                featured: p.featured,
                hidden: p.hidden || false,
                videoPreview: p.videoPreview
            }));

            // 2. Construct BN payload
            const bnItems = projects.map(p => ({
                title: p.bn.title,
                desc: p.bn.description,
                tags: p.tags,
                seo: p.seo,
                id: p.id,
                order: p.order,
                images: p.images,
                hoverImages: p.hoverImages || [],
                image: p.images[0] || '',
                link: p.link,
                categories: p.categories,
                category: p.categories[0] || 'SaaS',
                featured: p.featured,
                hidden: p.hidden || false,
                videoPreview: p.videoPreview
            }));

            // 3. Save both
            const enSuccess = await updateSection('projects', 'en', {
                title: sectionInfo.en.title,
                subtitle: sectionInfo.en.subtitle,
                categories: categories,
                items: enItems,
                visible: isVisible,
            });
            const bnSuccess = await updateSection('projects', 'bn', {
                title: sectionInfo.bn.title,
                subtitle: sectionInfo.bn.subtitle,
                items: bnItems,
                visible: isVisible,
            });

            if (enSuccess && bnSuccess) {
                setSaved(true);
                toast.success('Projects saved successfully', { id: toastId });
                window.dispatchEvent(new CustomEvent('orbit:save-success', { detail: { section: 'projects' } }));

                // Refresh content to ensure context is in sync
                await refreshContent();

                setTimeout(() => setSaved(false), 2000);
            } else {
                setError('Error saving projects. Please try again.');
                toast.error('Error saving projects', { id: toastId });
            }

        } catch (err) {
            console.error(err);
            setError('Failed to save projects. Please try again.');
            toast.error('Failed to save projects', { id: toastId });
        } finally {
            setSaving(false);
        }
    };

    if (loading) {
        return (
            <div className="space-y-6 animate-in fade-in duration-500">
                <div className="flex items-center justify-between">
                    <Skeleton className="h-8 w-64" />
                    <Skeleton className="h-6 w-32 rounded-full" />
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    <Skeleton className="h-40 rounded-2xl" />
                    <Skeleton className="h-40 rounded-2xl" />
                </div>
                <div className="space-y-4">
                    {[1, 2, 3].map((i) => (
                        <div key={i} className="flex flex-col gap-4 p-6 bg-card border border-border rounded-xl">
                            <div className="flex justify-between">
                                <Skeleton className="h-6 w-48" />
                                <Skeleton className="h-8 w-24 rounded-lg" />
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                                <Skeleton className="h-32 rounded-lg" />
                                <Skeleton className="h-32 rounded-lg" />
                                <Skeleton className="h-32 rounded-lg" />
                            </div>
                        </div>
                    ))}
                </div>
            </div>
        );
    }

    return (
        <div className="max-w-7xl mx-auto space-y-6">
            <div className="flex items-center justify-between flex-wrap gap-3">
                <SectionHeader title="Projects Manager (Unified)" description="Manage English and Bangla content in one place." />
                <div className="text-xs text-muted-foreground bg-secondary px-3 py-1 rounded-full">
                    Γ£à Dual-Language Mode Active
                </div>
            </div>

            <ErrorAlert message={error} />

            {/* Global Settings */}
            <div className="bg-card rounded-xl p-4 md:p-6 border border-border">
                <h3 className="font-semibold text-foreground mb-4 flex items-center gap-2">
                    <Settings2 className="w-4 h-4 text-primary" />
                    Global Portfolio Settings
                </h3>
                <div className="max-w-md">
                    <ToggleField 
                        label="Show Portfolio on Main Page" 
                        description="If disabled, the entire projects section will be hidden from the public site."
                        checked={isVisible}
                        onChange={setIsVisible}
                    />
                </div>
            </div>

            {/* Edit Section Title/Subtitle */}
            <div className="bg-card rounded-2xl border border-border overflow-hidden">
                <SectionHeader title="Section Title & Options" description="Configure English and Bangla titles and edit Categories for this section." />
                <div className="p-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                        <div className="space-y-4">
                            <h3 className="font-semibold text-foreground text-sm flex items-center gap-2">
                                <span className="w-1.5 h-1.5 rounded-full bg-blue-500"></span> English Context
                            </h3>
                            <TextField label="Section Title" value={sectionInfo.en.title} onChange={(v) => setSectionInfo(prev => ({ ...prev, en: { ...prev.en, title: v } }))} />
                            <TextField label="Section Subtitle" value={sectionInfo.en.subtitle} onChange={(v) => setSectionInfo(prev => ({ ...prev, en: { ...prev.en, subtitle: v } }))} />
                        </div>
                        <div className="space-y-4">
                            <h3 className="font-semibold text-foreground text-sm flex items-center gap-2">
                                <span className="w-1.5 h-1.5 rounded-full bg-green-500"></span> Bangla Context
                            </h3>
                            <TextField label="Section Title (BN)" value={sectionInfo.bn.title} onChange={(v) => setSectionInfo(prev => ({ ...prev, bn: { ...prev.bn, title: v } }))} />
                            <TextField label="Section Subtitle (BN)" value={sectionInfo.bn.subtitle} onChange={(v) => setSectionInfo(prev => ({ ...prev, bn: { ...prev.bn, subtitle: v } }))} />
                        </div>

                        {/* Manage Categories Section */}
                        <div className="space-y-4 lg:pl-6 lg:border-l lg:border-border">
                            <h3 className="font-semibold text-foreground text-sm flex items-center gap-2">
                                <Layers className="w-4 h-4 text-primary" /> Manage Categories
                            </h3>
                            <div className="flex flex-wrap gap-2">
                                {categories.map(cat => (
                                    <span key={cat} className="inline-flex items-center gap-1.5 bg-secondary text-foreground text-xs font-medium px-3 py-1.5 rounded-full border border-border/50">
                                        {cat}
                                        <button
                                            type="button"
                                            onClick={() => setCategories(categories.filter(c => c !== cat))}
                                            className="text-muted-foreground hover:text-red-500 transition-colors"
                                        >
                                            <Trash2 className="w-3 h-3" />
                                        </button>
                                    </span>
                                ))}
                            </div>
                            <div className="flex items-center gap-2 w-full pt-1">
                                <input
                                    type="text"
                                    value={newCategory}
                                    onChange={e => setNewCategory(e.target.value)}
                                    onKeyDown={e => {
                                        if (e.key === 'Enter' && newCategory.trim() && !categories.includes(newCategory.trim())) {
                                            setCategories([...categories, newCategory.trim()]);
                                            setNewCategory('');
                                        }
                                    }}
                                    placeholder="Add new category..."
                                    className="flex-1 bg-secondary rounded-lg px-4 py-2 text-sm text-foreground outline-none border border-border min-w-0"
                                />
                                <button
                                    type="button"
                                    onClick={() => {
                                        if (newCategory.trim() && !categories.includes(newCategory.trim())) {
                                            setCategories([...categories, newCategory.trim()]);
                                            setNewCategory('');
                                        }
                                    }}
                                    className="bg-primary/20 text-primary hover:bg-primary/30 px-3 py-2 rounded-lg transition-colors flex-shrink-0"
                                >
                                    <Plus className="w-4 h-4" />
                                </button>
                            </div>
                            <p className="text-[10px] text-muted-foreground leading-relaxed">Categories appear as filters on the frontend and in project editors.</p>
                        </div>
                    </div>
                </div>
            </div>

            {/* Reorder Projects Section */}
            <div className="bg-card rounded-xl p-4 md:p-6 border border-border">
                <div className="flex items-center justify-between mb-4">
                    <h3 className="font-semibold text-foreground flex items-center gap-2">
                        <GripVertical className="w-5 h-5 text-primary" /> Reorder Projects
                    </h3>
                    <div className="text-xs text-muted-foreground bg-secondary px-3 py-1 rounded-full">
                        Drag or click buttons to reorder
                    </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-3">
                    {projects.map((p, i) => (
                        <div key={p.id || i} className={`flex flex-col rounded-lg overflow-hidden border group transition-all ${
                            p.hidden 
                                ? 'bg-red-500/5 border-red-500/20 opacity-60' 
                                : 'bg-secondary/50 border-border'
                        }`}>
                            <div className="flex items-center p-2 gap-3 pb-1">
                                <span className="text-sm font-bold text-muted-foreground w-5 text-center flex-shrink-0">{i + 1}</span>
                                {p.images && p.images[0] ? (
                                    <div className={`w-10 h-10 rounded overflow-hidden flex-shrink-0 bg-background border ${p.hidden ? 'border-red-500/30 grayscale' : 'border-border'}`}>
                                        <img src={p.images[0]} alt="" className="w-full h-full object-cover" />
                                    </div>
                                ) : (
                                    <div className="w-10 h-10 rounded flex-shrink-0 bg-background border border-border flex flex-col items-center justify-center text-[8px] text-muted-foreground">
                                        No Image
                                    </div>
                                )}
                                <div className="flex-1 min-w-0">
                                    <div className="flex items-center gap-1.5">
                                        <h4 className={`text-sm font-semibold truncate ${p.hidden ? 'text-muted-foreground line-through' : 'text-foreground'}`}>{p.en.title || p.bn.title || 'Untitled Project'}</h4>
                                        {p.hidden && (
                                            <span className="flex-shrink-0 px-1.5 py-0.5 rounded bg-red-500/15 text-red-400 text-[9px] font-bold uppercase tracking-wider">Hidden</span>
                                        )}
                                    </div>
                                    <span className="text-[10px] text-muted-foreground bg-background px-1.5 py-0.5 rounded border border-border truncate max-w-full inline-block mt-0.5">
                                        {p.categories.join(', ')}
                                    </span>
                                </div>
                                <div className="flex flex-col gap-0.5 ml-auto">
                                    <button
                                        type="button"
                                        onClick={() => {
                                            if (i === 0) return;
                                            const updated = [...projects];
                                            [updated[i - 1], updated[i]] = [updated[i], updated[i - 1]];
                                            // Update explicit order property to match new array index
                                            const synced = updated.map((proj, idx) => ({ ...proj, order: idx }));
                                            setProjects(synced);
                                        }}
                                        disabled={i === 0}
                                        className="p-1.5 bg-background rounded border border-border hover:bg-primary hover:text-white hover:border-primary disabled:opacity-30 disabled:hover:bg-background disabled:hover:text-foreground disabled:hover:border-border transition-colors cursor-pointer"
                                        title="Move Up"
                                    >
                                        <ArrowUp className="w-3 h-3" />
                                    </button>
                                    <button
                                        type="button"
                                        onClick={() => {
                                            if (i === projects.length - 1) return;
                                            const updated = [...projects];
                                            [updated[i + 1], updated[i]] = [updated[i], updated[i + 1]];
                                            // Update explicit order property to match new array index
                                            const synced = updated.map((proj, idx) => ({ ...proj, order: idx }));
                                            setProjects(synced);
                                        }}
                                        disabled={i === projects.length - 1}
                                        className="p-1.5 bg-background rounded border border-border hover:bg-primary hover:text-white hover:border-primary disabled:opacity-30 disabled:hover:bg-background disabled:hover:text-foreground disabled:hover:border-border transition-colors cursor-pointer"
                                        title="Move Down"
                                    >
                                        <ArrowDown className="w-3 h-3" />
                                    </button>
                                </div>
                            </div>
                        </div>
                    ))}
                </div>
                <p className="text-[10px] text-muted-foreground mt-3 italic flex items-center justify-center gap-1.5">
                    Changes require clicking <strong>Save Changes</strong> at the bottom of the page.
                </p>
            </div>

            {/* Projects List */}
            <div className="bg-card rounded-xl p-4 md:p-6 border border-border">
                <div className="flex items-center justify-between mb-4">
                    <h3 className="font-semibold text-foreground">Projects Content Editor ({projects.length})</h3>
                </div>

                <ItemListEditor
                    items={projects}
                    setItems={(reordered) => {
                        // Sync the order field with the new array position
                        const synced = reordered.map((p, i) => ({ ...p, order: i }));
                        setProjects(synced);
                    }}
                    newItem={DEFAULT_PROJECT}
                    addLabel="Add New Project"
                    getItemLabel={(item) => item.en.title || item.bn.title || ''}
                    onSave={handleSave}
                    renderItem={(item, _i, update) => (
                        <ProjectEditor item={item} update={update} categories={categories} onSave={handleSave} />
                    )}
                />
            </div>

            <SaveButton onClick={handleSave} saving={saving} saved={saved} />

            <div className="mt-8 pt-8 border-t border-border">
                <JsonPanel
                    data={{
                        en: {
                            title: sectionInfo.en.title,
                            subtitle: sectionInfo.en.subtitle,
                            items: projects.map(p => ({
                                title: p.en.title,
                                desc: p.en.description,
                                tags: p.tags,
                                seo: p.seo,
                                id: p.id,
                                order: p.order,
                                images: p.images,
                                link: p.link,
                                categories: p.categories,
                                category: p.categories[0] || 'SaaS',
                                featured: p.featured,
                                videoPreview: p.videoPreview
                            }))
                        },
                        bn: {
                            title: sectionInfo.bn.title,
                            subtitle: sectionInfo.bn.subtitle,
                            items: projects.map(p => ({
                                title: p.bn.title,
                                desc: p.bn.description,
                                tags: p.tags,
                                seo: p.seo,
                                id: p.id,
                                order: p.order,
                                images: p.images,
                                link: p.link,
                                categories: p.categories,
                                category: p.categories[0] || 'SaaS',
                                featured: p.featured,
                                videoPreview: p.videoPreview
                            }))
                        }
                    }}
                    onImport={(parsed) => {
                        if (!parsed.en || !parsed.bn) {
                            toast.error('JSON must have "en" and "bn" keys');
                            return;
                        }
                        setSectionInfo({
                            en: { title: parsed.en.title || '', subtitle: parsed.en.subtitle || '' },
                            bn: { title: parsed.bn.title || '', subtitle: parsed.bn.subtitle || '' }
                        });
                        const enItems = parsed.en.items || [];
                        const bnItems = parsed.bn.items || [];
                        const maxLen = Math.max(enItems.length, bnItems.length);
                        const merged: UnifiedProject[] = [];
                        for (let i = 0; i < maxLen; i++) {
                            const en = enItems[i] || {};
                            const bn = bnItems[i] || {};
                            const importCats = en.categories || bn.categories || (en.category ? [en.category] : (bn.category ? [bn.category] : ['SaaS']));
                            merged.push({
                                id: en.id || bn.id || '',
                                order: en.order ?? bn.order ?? i,
                                images: en.images || bn.images || [],
                                hoverImages: en.hoverImages || bn.hoverImages || [],
                                link: en.link || bn.link || '',
                                categories: Array.isArray(importCats) ? importCats : [importCats],
                                featured: en.featured ?? bn.featured ?? false,
                                hidden: en.hidden ?? bn.hidden ?? false,
                                videoPreview: en.videoPreview || bn.videoPreview || '',
                                tags: en.tags || bn.tags || [],
                                seo: en.seo || bn.seo || { title: '', description: '', keywords: [] },
                                en: {
                                    title: en.title || '',
                                    description: en.desc || ''
                                },
                                bn: {
                                    title: bn.title || '',
                                    description: bn.desc || ''
                                }
                            });
                        }
                        setProjects(merged);
                    }}
                />
            </div>
        </div>
    );
}

import { useState, useEffect } from 'react';
import { SectionHeader, LangToggle, SaveButton, TextField, ToggleField, ErrorAlert, useSectionEditor, JsonPanel } from '@/components/admin/EditorComponents';
import { Star, Plus, Trash2, ChevronUp, ChevronDown, Mail, MessageCircle, ShoppingBag, Briefcase, Globe, AtSign, Hash, Instagram, Facebook, Twitter, Linkedin, Github } from 'lucide-react';
import { useContent } from '@/contexts/ContentContext';

const WhatsAppIcon = ({ className }: { className?: string }) => (
    <svg viewBox="0 0 24 24" fill="currentColor" className={className}>
        <path d="M17.472 14.382c-.297-.149-1.758-.867-2.03-.967-.273-.099-.471-.148-.67.15-.197.297-.767.966-.94 1.164-.173.199-.347.223-.644.075-.297-.15-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.298-.347.446-.52.149-.174.198-.298.298-.497.099-.198.05-.371-.025-.52-.075-.149-.669-1.612-.916-2.207-.242-.579-.487-.5-.669-.51-.173-.008-.371-.01-.57-.01-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.625.712.227 1.36.195 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.694.248-1.289.173-1.413-.074-.124-.272-.198-.57-.347m-5.421 7.403h-.004a9.87 9.87 0 01-5.031-1.378l-.361-.214-3.741.982.998-3.648-.235-.374a9.86 9.86 0 01-1.51-5.26c.001-5.45 4.436-9.884 9.888-9.884 2.64 0 5.122 1.03 6.988 2.898a9.825 9.825 0 012.893 6.994c-.003 5.45-4.437 9.884-9.885 9.884m8.413-18.297A11.815 11.815 0 0012.05 0C5.495 0 .16 5.335.157 11.892c0 2.096.547 4.142 1.588 5.945L.057 24l6.305-1.654a11.882 11.882 0 005.683 1.448h.005c6.554 0 11.89-5.335 11.893-11.893a11.821 11.821 0 00-3.48-8.413z" />
    </svg>
);

interface ReviewItem {
    name: string;
    role: string;
    avatar: string;
    rating: number;
    text: string;
    projectId: string;
    projectName: string;
    badgeName: string;
    hidden: boolean;
    social?: {
        google?: { url: string; enabled: boolean };
        whatsapp?: { url: string; enabled: boolean };
        instagram?: { url: string; enabled: boolean };
        facebook?: { url: string; enabled: boolean };
        threads?: { url: string; enabled: boolean };
        twitter?: { url: string; enabled: boolean };
        fiverr?: { url: string; enabled: boolean };
        upwork?: { url: string; enabled: boolean };
        linkedin?: { url: string; enabled: boolean };
        github?: { url: string; enabled: boolean };
    };
}

const emptyReview: ReviewItem = { 
    name: '', 
    role: '', 
    avatar: '', 
    rating: 5, 
    text: '', 
    projectId: '', 
    projectName: '', 
    badgeName: '', 
    hidden: false,
    social: {} 
};

export default function AdminReviews() {
    const { lang, setLang, saving, saved, error, getData, save } = useSectionEditor('reviews');
    const { content } = useContent();

    const [title, setTitle] = useState('Client Reviews');
    const [subtitle, setSubtitle] = useState('What our clients say about working with us');
    const [items, setItems] = useState<ReviewItem[]>([]);
    const [showSocials, setShowSocials] = useState(true);

    // Get project list for dropdown
    const enProjects = (content.en as any).projects;
    const projectItems: any[] = Array.isArray(enProjects?.items) ? enProjects.items : [];

    useEffect(() => {
        const d = getData();
        if (d) {
            const rawItems = Array.isArray(d) ? d : (d.items || []);
            setShowSocials(d.showSocials ?? true);
            
            setItems(rawItems.map((item: any) => ({
                name: item.name || '',
                role: item.role || '',
                avatar: item.avatar || '',
                rating: item.rating ?? 5,
                text: item.text || '',
                projectId: item.projectId || '',
                projectName: item.projectName || '',
                badgeName: item.badgeName || '',
                hidden: item.hidden ?? false,
                social: item.social ? Object.fromEntries(
                    Object.entries(item.social).map(([k, v]) => [
                        k,
                        typeof v === 'string' ? { url: v, enabled: true } : (v as any)
                    ])
                ) : { ...emptyReview.social },
            })));
        }
    }, [getData]);

    const handleSave = async () => {
        await save({
            title,
            subtitle,
            items,
            showSocials
        });
    };

    const updateItem = (idx: number, field: keyof ReviewItem, value: any) => {
        setItems(prev => prev.map((item, i) => {
            if (i !== idx) return item;
            const updated = { ...item, [field]: value };
            // Auto-fill project name from dropdown
            if (field === 'projectId' && typeof value === 'string') {
                const proj = projectItems.find((p: any) => (p.id || '') === value);
                if (proj) {
                    updated.projectName = proj.title || '';
                    // Auto-fill badge name only if empty
                    if (!updated.badgeName) updated.badgeName = proj.title || '';
                }
            }
            return updated;
        }));
    };

    const addItem = () => setItems(prev => [...prev, { ...emptyReview }]);
    const removeItem = (idx: number) => setItems(prev => prev.filter((_, i) => i !== idx));

    const moveItem = (idx: number, dir: -1 | 1) => {
        const newIdx = idx + dir;
        if (newIdx < 0 || newIdx >= items.length) return;
        setItems(prev => {
            const next = [...prev];
            [next[idx], next[newIdx]] = [next[newIdx], next[idx]];
            return next;
        });
    };

    const updateSocial = (idx: number, platform: string, field: 'url' | 'enabled', value: any) => {
        setItems(prev => prev.map((item, i) => {
            if (i !== idx) return item;
            const currentSocial = item.social?.[platform as keyof NonNullable<ReviewItem['social']>] || { url: '', enabled: false };
            const normalized = typeof currentSocial === 'string' ? { url: currentSocial, enabled: true } : currentSocial;
            return {
                ...item,
                social: {
                    ...item.social,
                    [platform]: {
                        ...normalized,
                        [field]: value
                    }
                }
            };
        }));
    };

    const ReviewSocialField = ({ idx, label, platform, icon: Icon }: { idx: number, label: string, platform: string, icon?: any }) => {
        const item = items[idx].social?.[platform as keyof NonNullable<ReviewItem['social']>] || { url: '', enabled: false };
        return (
            <div className="flex items-center justify-between gap-2 p-2 rounded-lg bg-secondary/10 border border-border/30 group/socket transition-all hover:bg-secondary/20 hover:border-primary/30">
                <div className="flex items-center gap-1.5">
                    {Icon && <Icon className="w-3 h-3 text-muted-foreground group-hover/socket:text-primary transition-colors" />}
                    <span className="text-[10px] font-bold text-muted-foreground uppercase tracking-wider group-hover/socket:text-foreground">{label}</span>
                </div>
                <button
                    type="button"
                    onClick={() => updateSocial(idx, platform, 'enabled', !item.enabled)}
                    className={`relative inline-flex h-4 w-7 items-center rounded-full transition-colors focus:outline-none cursor-pointer ${item.enabled ? 'bg-primary' : 'bg-muted'}`}
                >
                    <span className={`inline-block h-2.5 w-2.5 transform rounded-full bg-white transition-transform ${item.enabled ? 'translate-x-4' : 'translate-x-0.5'}`} />
                </button>
            </div>
        );
    };

    const currentPayload = { title, subtitle, items, showSocials };

    return (
        <div className="space-y-6">
            <div className="flex items-center justify-between flex-wrap gap-3">
                <SectionHeader title="Reviews" description="Manage client reviews linked to projects" />
                <LangToggle lang={lang} setLang={setLang} />
            </div>
            <ErrorAlert message={error} />

            {/* Section Header Fields */}
            <div className="bg-card rounded-xl p-4 md:p-6 border border-border space-y-4">
                <h3 className="font-semibold text-foreground flex items-center gap-2">≡ƒô¥ Section Header</h3>
                <TextField label="Title" value={title} onChange={setTitle} lang={lang} />
                <TextField label="Subtitle" value={subtitle} onChange={setSubtitle} lang={lang} />
                
                <ToggleField
                    label="Show Social Icons on Review Cards"
                    description="If enabled, social media and marketplace icons will be shown on each review card where links are provided."
                    checked={showSocials}
                    onChange={setShowSocials}
                />
            </div>

            {/* Review Items */}
            <div className="space-y-4">
                <div className="flex items-center justify-between">
                    <h3 className="font-semibold text-foreground flex items-center gap-2">Γ¡É Reviews ({items.length})</h3>
                    <button
                        onClick={addItem}
                        className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-lg bg-emerald-500/20 text-emerald-500 text-sm font-medium border border-emerald-500/30 hover:bg-emerald-500/30 transition-all cursor-pointer"
                    >
                        <Plus className="w-4 h-4" /> Add Review
                    </button>
                </div>

                {items.map((item, idx) => (
                    <div key={idx} className="bg-card rounded-xl p-5 border border-border space-y-4 relative">
                        <div className="flex items-center justify-between">
                            <span className="text-sm font-bold text-muted-foreground">Review #{idx + 1}</span>
                            <div className="flex items-center gap-1">
                                {/* Reorder Buttons */}
                                <button
                                    onClick={() => moveItem(idx, -1)}
                                    disabled={idx === 0}
                                    className="p-1.5 rounded-lg text-muted-foreground hover:bg-white/5 transition-colors cursor-pointer disabled:opacity-30 disabled:cursor-not-allowed"
                                    title="Move up"
                                >
                                    <ChevronUp className="w-4 h-4" />
                                </button>
                                <button
                                    onClick={() => moveItem(idx, 1)}
                                    disabled={idx === items.length - 1}
                                    className="p-1.5 rounded-lg text-muted-foreground hover:bg-white/5 transition-colors cursor-pointer disabled:opacity-30 disabled:cursor-not-allowed"
                                    title="Move down"
                                >
                                    <ChevronDown className="w-4 h-4" />
                                </button>
                                <button
                                    onClick={() => removeItem(idx)}
                                    className="p-1.5 rounded-lg text-red-400 hover:bg-red-500/10 transition-colors cursor-pointer"
                                >
                                    <Trash2 className="w-4 h-4" />
                                </button>
                            </div>
                        </div>

                        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                            <div className="grid gap-4 sm:grid-cols-2">
                                <TextField label="Reviewer Name" value={item.name} onChange={(v) => updateItem(idx, 'name', v)} lang={lang} />
                                <TextField label="Role / Company" value={item.role} onChange={(v) => updateItem(idx, 'role', v)} lang={lang} />
                            </div>
                            <div>
                                <label className="text-sm font-medium text-foreground block mb-1.5">Visibility</label>
                                <div className="flex items-center gap-3 bg-secondary rounded-lg px-4 py-2.5 border border-border h-[42px]">
                                    <button
                                        type="button"
                                        onClick={() => updateItem(idx, 'hidden', !item.hidden)}
                                        className={`relative w-11 h-6 rounded-full transition-colors duration-300 focus:outline-none focus:ring-2 focus:ring-primary/30 ${item.hidden ? 'bg-red-500/80' : 'bg-emerald-500'
                                            }`}
                                    >
                                        <span className={`absolute top-0.5 left-0.5 w-5 h-5 rounded-full bg-white shadow-sm transition-transform duration-300 ${item.hidden ? 'translate-x-0' : 'translate-x-5'
                                            }`} />
                                    </button>
                                    <span className={`text-sm font-medium ${item.hidden ? 'text-red-400' : 'text-emerald-500'}`}>
                                        {item.hidden ? '≡ƒö┤ Hidden' : '≡ƒƒó Visible'}
                                    </span>
                                </div>
                            </div>
                        </div>
                        <TextField label="Avatar URL" value={item.avatar} onChange={(v) => updateItem(idx, 'avatar', v)} />

                        {/* Rating Stars */}
                        <div>
                            <label className="text-sm font-medium text-muted-foreground block mb-1.5">Rating</label>
                            <div className="flex gap-1">
                                {[1, 2, 3, 4, 5].map(star => (
                                    <button
                                        key={star}
                                        onClick={() => updateItem(idx, 'rating', star)}
                                        className="cursor-pointer transition-transform hover:scale-110"
                                    >
                                        <Star
                                            className={`w-6 h-6 ${star <= item.rating ? 'text-amber-400 fill-amber-400' : 'text-white/20'}`}
                                        />
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* Review Text ΓÇö dark themed textarea */}
                        <div>
                            <label className="text-sm font-medium text-muted-foreground block mb-1.5">Review Text</label>
                            <textarea
                                value={item.text}
                                onChange={(e) => updateItem(idx, 'text', e.target.value)}
                                rows={3}
                                placeholder="Write the review text here..."
                                className="w-full rounded-lg bg-secondary border border-border px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground/50 resize-y focus:outline-none focus:ring-1 focus:ring-primary"
                            />
                        </div>

                        {/* Project Dropdown */}
                        <div>
                            <label className="text-sm font-medium text-muted-foreground block mb-1.5">Linked Project</label>
                            <select
                                value={item.projectId}
                                onChange={(e) => updateItem(idx, 'projectId', e.target.value)}
                                className="w-full rounded-lg bg-secondary border border-border px-3 py-2 text-sm text-foreground focus:outline-none focus:ring-1 focus:ring-primary cursor-pointer"
                            >
                                <option value="">ΓÇö None ΓÇö</option>
                                {projectItems.map((proj: any, pi: number) => (
                                    <option key={pi} value={proj.id || String(pi)}>
                                        {proj.title || `Project ${pi + 1}`}
                                    </option>
                                ))}
                            </select>
                        </div>

                        {/* Badge Name (custom label for the project badge on the card) */}
                        <div>
                            <label className="text-sm font-medium text-muted-foreground block mb-1.5">Badge Name <span className="text-muted-foreground/50 text-xs">(custom name shown on the review card badge)</span></label>
                            <input
                                type="text"
                                value={item.badgeName}
                                onChange={(e) => updateItem(idx, 'badgeName', e.target.value)}
                                placeholder={item.projectName || 'e.g. LifeSolver'}
                                className="w-full rounded-lg bg-secondary border border-border px-3 py-2 text-sm text-foreground placeholder:text-muted-foreground/50 focus:outline-none focus:ring-1 focus:ring-primary"
                            />
                        </div>

                        {/* Social Links */}
                        <div className="pt-4 border-t border-border mt-4">
                            <label className="text-sm font-bold text-foreground block mb-4">≡ƒöù Reviewer Social / Marketplace Links</label>
                            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
                                <ReviewSocialField idx={idx} label="Google" platform="google" icon={Mail} />
                                <ReviewSocialField idx={idx} label="WhatsApp" platform="whatsapp" icon={WhatsAppIcon} />
                                <ReviewSocialField idx={idx} label="Instagram" platform="instagram" icon={Instagram} />
                                <ReviewSocialField idx={idx} label="Facebook" platform="facebook" icon={Facebook} />
                                <ReviewSocialField idx={idx} label="Threads" platform="threads" icon={AtSign} />
                                <ReviewSocialField idx={idx} label="Twitter" platform="twitter" icon={Twitter} />
                                <ReviewSocialField idx={idx} label="Fiverr" platform="fiverr" icon={Briefcase} />
                                <ReviewSocialField idx={idx} label="Upwork" platform="upwork" icon={Globe} />
                                <ReviewSocialField idx={idx} label="LinkedIn" platform="linkedin" icon={Linkedin} />
                                <ReviewSocialField idx={idx} label="GitHub" platform="github" icon={Github} />
                            </div>
                        </div>
                    </div>
                ))}

                {items.length === 0 && (
                    <div className="text-center py-10 text-muted-foreground text-sm border border-dashed border-border rounded-xl">
                        No reviews yet. Click "Add Review" to create one.
                    </div>
                )}
            </div>

            <SaveButton onClick={handleSave} saving={saving} saved={saved} />

            <div className="mt-8 pt-8 border-t border-border">
                <JsonPanel
                    title={`JSON Import / Export (${lang.toUpperCase()})`}
                    data={currentPayload}
                    onImport={(parsed: any) => {
                        if (parsed.title) setTitle(parsed.title);
                        if (parsed.subtitle) setSubtitle(parsed.subtitle);
                        if (parsed.showSocials !== undefined) setShowSocials(parsed.showSocials);
                        if (parsed.items && Array.isArray(parsed.items)) {
                            setItems(parsed.items.map((item: any) => ({
                                name: item.name || '',
                                role: item.role || '',
                                avatar: item.avatar || '',
                                rating: item.rating ?? 5,
                                text: item.text || '',
                                projectId: item.projectId || '',
                                projectName: item.projectName || '',
                                badgeName: item.badgeName || '',
                                social: item.social ? Object.fromEntries(
                                    Object.entries(item.social).map(([k, v]) => [
                                        k,
                                        typeof v === 'string' ? { url: v, enabled: true } : (v as any)
                                    ])
                                ) : {},
                            })));
                        }
                    }}
                />
            </div>
        </div>
    );
}

import { useState, useEffect, useRef } from 'react';
import { toast } from 'sonner';
import { SectionHeader, SaveButton, TextField, ErrorAlert, JsonPanel, ColorField } from '@/components/admin/EditorComponents';
import { Settings2, Paintbrush, Palette, ChevronDown, Plus, Trash2, ArrowUp, ArrowDown, GripVertical, Eye, Layers, Sparkles, Globe, Bot, Zap, Smartphone, ShoppingCart, Rocket, Code, Database, Shield, Cloud, Cpu, Monitor, Wifi, Mail, Camera, Music, Heart, Star, Target, Briefcase, Award, BookOpen, Users, BarChart3 } from 'lucide-react';
import { useContent } from '@/contexts/ContentContext';
import type { LucideIcon } from 'lucide-react';

// ΓöÇΓöÇΓöÇ Icon Registry ΓöÇΓöÇΓöÇ
const ICON_MAP: Record<string, LucideIcon> = {
    Globe, Bot, Zap, Smartphone, ShoppingCart, Rocket, Code, Database, Shield, Cloud,
    Cpu, Monitor, Wifi, Mail, Camera, Music, Heart, Star, Target, Briefcase,
    Award, BookOpen, Users, BarChart3, Sparkles, Layers, Settings2, Eye, Palette
};
const ICON_NAMES = Object.keys(ICON_MAP);
const DEFAULT_ICONS = ['Globe', 'Bot', 'Zap', 'Smartphone', 'ShoppingCart', 'Rocket'];

// ΓöÇΓöÇΓöÇ Types ΓöÇΓöÇΓöÇ
interface ServiceText {
    title: string;
    desc: string;
    badge: string;
}

interface UnifiedService {
    en: ServiceText;
    bn: ServiceText;
    icon?: string; // Lucide icon name e.g. 'Globe'
    color?: string;
    border?: string;
}

const DEFAULT_ITEM: UnifiedService = {
    en: { title: '', desc: '', badge: '' },
    bn: { title: '', desc: '', badge: '' },
    icon: '',
};

// ΓöÇΓöÇΓöÇ Elegant Service Card Editor ΓöÇΓöÇΓöÇ
function ServiceCard({
    item,
    update,
    onRemove,
    onMoveUp,
    onMoveDown,
    index,
    total,
    iconColor,
    cardBorder,
}: {
    item: UnifiedService;
    update: (m: UnifiedService) => void;
    onRemove: () => void;
    onMoveUp: () => void;
    onMoveDown: () => void;
    index: number;
    total: number;
    iconColor: string;
    cardBorder: string;
}) {
    const [expanded, setExpanded] = useState(false);
    const [tab, setTab] = useState<'en' | 'bn'>('en');
    const [showAdvanced, setShowAdvanced] = useState(false);
    const [showIconPicker, setShowIconPicker] = useState(false);
    const accentColor = item.color || iconColor;
    const currentIconName = item.icon || DEFAULT_ICONS[index % DEFAULT_ICONS.length];
    const CurrentIcon = ICON_MAP[currentIconName] || Globe;

    const updateLoc = (lang: 'en' | 'bn', field: keyof ServiceText, value: string) => {
        update({ ...item, [lang]: { ...item[lang], [field]: value } });
    };

    const cardTitle = item.en.title || item.bn.title || 'Untitled Module';

    return (
        <div
            className={`group relative rounded-2xl border transition-all duration-300 overflow-hidden ${expanded
                ? 'bg-card border-primary/30 shadow-lg shadow-primary/5 ring-1 ring-primary/10'
                : 'bg-card/60 border-border/60 hover:border-border hover:shadow-md'
                }`}
        >
            {/* Accent top line */}
            <div
                className="absolute top-0 left-0 right-0 h-[2px] transition-all duration-300"
                style={{ background: expanded ? `linear-gradient(90deg, ${accentColor}, ${accentColor}40)` : 'transparent' }}
            />

            {/* Collapsed Header */}
            <div
                className="flex items-center gap-3 px-5 py-4 cursor-pointer select-none"
                onClick={() => setExpanded(!expanded)}
            >
                {/* Order & Drag indicator */}
                <div className="flex flex-col items-center gap-0.5 text-muted-foreground/40 group-hover:text-muted-foreground/70 transition-colors">
                    <GripVertical className="w-4 h-4" />
                </div>

                {/* Icon + Number badge */}
                <div
                    className="w-9 h-9 rounded-xl flex items-center justify-center shrink-0 transition-all"
                    style={{
                        backgroundColor: `${accentColor}15`,
                        border: `1px solid ${accentColor}25`
                    }}
                >
                    <CurrentIcon className="w-4.5 h-4.5" style={{ color: accentColor }} />
                </div>

                {/* Title & preview */}
                <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2">
                        <span className="text-[10px] font-mono text-muted-foreground/50">#{String(index + 1).padStart(2, '0')}</span>
                        <h4 className="text-sm font-semibold text-foreground truncate">{cardTitle}</h4>
                    </div>
                    {item.en.desc && !expanded && (
                        <p className="text-xs text-muted-foreground truncate mt-0.5 max-w-md">{item.en.desc.slice(0, 80)}ΓÇª</p>
                    )}
                </div>

                {/* Color dot preview */}
                <div
                    className="w-3 h-3 rounded-full ring-2 ring-offset-2 ring-offset-card shrink-0 transition-all"
                    style={{ backgroundColor: accentColor }}
                    title={`Accent: ${accentColor}`}
                />

                {/* Actions */}
                <div className="flex items-center gap-1 shrink-0">
                    <button
                        onClick={(e) => { e.stopPropagation(); onMoveUp(); }}
                        disabled={index === 0}
                        className="w-7 h-7 rounded-lg flex items-center justify-center text-muted-foreground hover:text-foreground hover:bg-secondary disabled:opacity-20 disabled:pointer-events-none transition-all"
                        title="Move up"
                    >
                        <ArrowUp className="w-3.5 h-3.5" />
                    </button>
                    <button
                        onClick={(e) => { e.stopPropagation(); onMoveDown(); }}
                        disabled={index === total - 1}
                        className="w-7 h-7 rounded-lg flex items-center justify-center text-muted-foreground hover:text-foreground hover:bg-secondary disabled:opacity-20 disabled:pointer-events-none transition-all"
                        title="Move down"
                    >
                        <ArrowDown className="w-3.5 h-3.5" />
                    </button>
                    <button
                        onClick={(e) => { e.stopPropagation(); if (window.confirm(`Delete "${cardTitle}"?`)) onRemove(); }}
                        className="w-7 h-7 rounded-lg flex items-center justify-center text-muted-foreground hover:text-red-500 hover:bg-red-500/10 transition-all"
                        title="Remove"
                    >
                        <Trash2 className="w-3.5 h-3.5" />
                    </button>
                    <div className={`w-7 h-7 rounded-lg flex items-center justify-center text-muted-foreground transition-all ${expanded ? 'rotate-180' : ''}`}>
                        <ChevronDown className="w-4 h-4" />
                    </div>
                </div>
            </div>

            {/* Expanded Content */}
            {expanded && (
                <div className="border-t border-border/40">
                    {/* Language tabs */}
                    <div className="flex bg-secondary/20">
                        {(['en', 'bn'] as const).map(lang => (
                            <button
                                key={lang}
                                onClick={() => setTab(lang)}
