    ItemListEditor,
    JsonPanel,
} from '@/components/admin/EditorComponents';
import { useContent } from '@/contexts/ContentContext';

// ΓöÇΓöÇΓöÇ Types ΓöÇΓöÇΓöÇ

interface TechCategory {
    name: string;
    items: string[];
}

interface UnifiedTechCategory {
    color: string;
